// ============================================================
// REGRA P├ëTREA UL-MAXIMIZER
// ============================================================
// Fun├º├úo Objetivo: Maximizar UL (Utility/Lucro)
//   UL = ╬ú(Reward Wins capturados) - ╬ú(Penalty Losses) - ╬ú(Custo Oportunidade Wins perdidos)
//
// Hierarquia:
//   1. Evitar LOSS (custo -3.0, mais caro que qualquer win exceto TP3)
//   2. Capturar WIN_TP2/TP3 (+2.0/+3.0, compensa losses)
//   3. Preferir NEUTRO ao risco (NEUTRO que evita loss = +1.5)
//   4. N├úo perder oportunidades (WIN_TP3 perdido custa -1.0)
// ============================================================

// UL reward/penalty table by status
const UL_VALUES: Record<string, number> = {
  WIN_TP3: 3.0,
  WIN_TP2: 2.0,
  WIN_TP1: 1.0,
  WIN: 1.0,        // generic win = TP1
  LOSS: -3.0,
};

// Cost of missing a win (opportunity cost when we go NEUTRAL on a winning trade)
const UL_MISSED_COST: Record<string, number> = {
  WIN_TP3: -1.0,
  WIN_TP2: -0.6,
  WIN_TP1: -0.3,
  WIN: -0.3,
};

// Reward for avoiding a loss (correctly going NEUTRAL on a losing trade)
const UL_LOSS_AVOIDED = 1.5;

// Reward for correct neutral (signal was neutral, stayed neutral)
const UL_NEUTRAL_CORRECT = 0.2;

// All known indicator names from the confluence engine
const ALL_INDICATORS = [
  "ICHIMOKU", "EMA200", "BOS", "EMA_ALIGNMENT", "EMA_CROSSOVER",
  "MACD_HIST", "MACD_LINE", "MACD_SLOPE", "MACD_ACCEL", "ADX_DIR", "RSI_SLOPE",
  "SMA10", "SMA20", "SMA50", "SMA100", "SMA200",
  "EMA10", "EMA20", "EMA50", "EMA100",
  "VWAP", "OBV_SLOPE", "MFI", "VOL_DELTA", "TAKER_BUY",
  "RSI", "STOCH", "BOLL", "CCI", "WILLIAMS_R", "AO", "MOMENTUM", "STOCH_RSI", "BULL_BEAR", "ULT_OSC",
  "OPEN_INTEREST", "FEAR_GREED", "FUNDING_RATE", "MC_REGIME",
  "FIB_PROXIMITY", "DIV_RSI", "DIV_MACD",
  "DOJI", "HAMMER", "SHOOTING_STAR", "BULLISH_ENGULFING", "BEARISH_ENGULFING", "MORNING_STAR", "EVENING_STAR",
];

// Default weights from the confluence engine
const DEFAULT_WEIGHTS: Record<string, number> = {
  ICHIMOKU: 2.0, EMA200: 1.5, BOS: 2.0, EMA_ALIGNMENT: 1.5, EMA_CROSSOVER: 2.5,
  MACD_HIST: 2.0, MACD_LINE: 2.0, MACD_SLOPE: 1.5, MACD_ACCEL: 1.0, ADX_DIR: 2.0, RSI_SLOPE: 1.5,
  SMA10: 1.0, SMA20: 1.0, SMA50: 1.0, SMA100: 1.0, SMA200: 1.0,
  EMA10: 1.0, EMA20: 1.0, EMA50: 1.0, EMA100: 1.0,
  VWAP: 2.0, OBV_SLOPE: 2.0, MFI: 1.0, VOL_DELTA: 1.5, TAKER_BUY: 2.0,
  RSI: 1.5, STOCH: 1.0, BOLL: 1.0, CCI: 1.0, WILLIAMS_R: 1.0, AO: 1.0, MOMENTUM: 1.0, STOCH_RSI: 1.0, BULL_BEAR: 1.0, ULT_OSC: 1.0,
  OPEN_INTEREST: 1.5, FEAR_GREED: 1.5, FUNDING_RATE: 1.0, MC_REGIME: 1.5,
  FIB_PROXIMITY: 1.5, DIV_RSI: 2.5, DIV_MACD: 2.5,
  DOJI: 1.0, HAMMER: 1.0, SHOOTING_STAR: 1.0, BULLISH_ENGULFING: 2.0, BEARISH_ENGULFING: 2.0, MORNING_STAR: 2.0, EVENING_STAR: 2.0,
};

// ============================================================
// TEMPORAL DECAY: Recent data matters more
// ============================================================
function getTemporalWeight(createdAt: string): number {
  const ageMs = Date.now() - new Date(createdAt).getTime();
  const ageDays = ageMs / (1000 * 60 * 60 * 24);
  if (ageDays <= 7) return 1.0;
  if (ageDays <= 30) return 0.7;
  if (ageDays <= 90) return 0.4;
  return 0.2;
}

// ============================================================
// INDICATOR DIRECTION EXTRACTION (shared logic)
// ============================================================
function extractIndicatorDirections(fr: any): Array<{ name: string; direction: string }> {
  const results: Array<{ name: string; direction: string }> = [];
  const ti = fr.technical_indicators || {};
  const entryP = fr.risk_management?.entry_price || 0;

  if (ti.rsi) {
    const dir = ti.rsi.value > 70 ? "SELL" : ti.rsi.value < 30 ? "BUY" : "NEUTRAL";
    results.push({ name: "RSI", direction: dir });
  }
  if (ti.macd) {
    results.push({ name: "MACD_HIST", direction: ti.macd.histogram > 0 ? "BUY" : ti.macd.histogram < 0 ? "SELL" : "NEUTRAL" });
    results.push({ name: "MACD_LINE", direction: ti.macd.value > ti.macd.signal_line ? "BUY" : "SELL" });
  }
  if (ti.adx && ti.adx.value > 20) {
    const signal = fr.header?.signal || "NEUTRO";
    const isBuy = signal === "COMPRA" || signal === "BUY";
    const isSell = signal === "VENDA" || signal === "SELL";
    results.push({ name: "ADX_DIR", direction: isBuy ? "BUY" : isSell ? "SELL" : "NEUTRAL" });
  }
  if (ti.stochastic) {
    results.push({ name: "STOCH", direction: ti.stochastic.k < 30 ? "BUY" : ti.stochastic.k > 70 ? "SELL" : "NEUTRAL" });
  }
  if (ti.bollinger && entryP) {
    results.push({ name: "BOLL", direction: entryP < ti.bollinger.lower ? "BUY" : entryP > ti.bollinger.upper ? "SELL" : "NEUTRAL" });
  }
  if (ti.cci !== undefined) {
    results.push({ name: "CCI", direction: ti.cci < -100 ? "BUY" : ti.cci > 100 ? "SELL" : "NEUTRAL" });
  }
  if (ti.mfi !== undefined) {
    results.push({ name: "MFI", direction: ti.mfi < 20 ? "BUY" : ti.mfi > 80 ? "SELL" : "NEUTRAL" });
  }
  if (ti.ichimoku) {
    results.push({ name: "ICHIMOKU", direction: ti.ichimoku.signal === "BULLISH" ? "BUY" : ti.ichimoku.signal === "BEARISH" ? "SELL" : "NEUTRAL" });
  }
  if (ti.vwap && entryP) {
    results.push({ name: "VWAP", direction: entryP > ti.vwap * 1.001 ? "BUY" : entryP < ti.vwap * 0.999 ? "SELL" : "NEUTRAL" });
  }
  if (ti.ema_20 && ti.ema_50 && ti.ema_200) {
    if (ti.ema_20 > ti.ema_50 && ti.ema_50 > ti.ema_200) results.push({ name: "EMA_ALIGNMENT", direction: "BUY" });
    else if (ti.ema_20 < ti.ema_50 && ti.ema_50 < ti.ema_200) results.push({ name: "EMA_ALIGNMENT", direction: "SELL" });
    else results.push({ name: "EMA_ALIGNMENT", direction: "NEUTRAL" });
    results.push({ name: "EMA20", direction: entryP > ti.ema_20 ? "BUY" : "SELL" });
    results.push({ name: "EMA50", direction: entryP > ti.ema_50 ? "BUY" : "SELL" });
    results.push({ name: "EMA200", direction: entryP > ti.ema_200 ? "BUY" : "SELL" });
  }
  if (fr._obv_slope) {
    results.push({ name: "OBV_SLOPE", direction: fr._obv_slope.obvTrend === "ACCUMULATION" ? "BUY" : fr._obv_slope.obvTrend === "DISTRIBUTION" ? "SELL" : "NEUTRAL" });
  }
  if (fr._volume_delta) {
    results.push({ name: "VOL_DELTA", direction: fr._volume_delta.pressure === "COMPRADORES" ? "BUY" : fr._volume_delta.pressure === "VENDEDORES" ? "SELL" : "NEUTRAL" });
  }
  if (fr._taker_data) {
    results.push({ name: "TAKER_BUY", direction: fr._taker_data.pressure === "COMPRADORES_AGRESSIVOS" ? "BUY" : fr._taker_data.pressure === "VENDEDORES_AGRESSIVOS" ? "SELL" : "NEUTRAL" });
  }
  if (fr._fear_greed) {
    results.push({ name: "FEAR_GREED", direction: fr._fear_greed.value < 25 ? "BUY" : fr._fear_greed.value > 75 ? "SELL" : "NEUTRAL" });
  }
  if (fr._funding_rate !== null && fr._funding_rate !== undefined) {
    results.push({ name: "FUNDING_RATE", direction: fr._funding_rate > 0.0005 ? "SELL" : fr._funding_rate < -0.0005 ? "BUY" : "NEUTRAL" });
  }
  if (ti.divergences) {
    ti.divergences.forEach((d: any) => {
      results.push({ name: `DIV_${d.indicator}`, direction: d.type === "BULLISH" ? "BUY" : "SELL" });
    });
  }
  if (ti.candle_patterns) {
    ti.candle_patterns.forEach((p: any) => {
      results.push({ name: p.name, direction: p.type === "BULLISH" ? "BUY" : "SELL" });
    });
  }
  if (fr._rsi_momentum) {
    results.push({ name: "RSI_SLOPE", direction: fr._rsi_momentum.direction === "ACCELERATING" ? "BUY" : fr._rsi_momentum.direction === "DECELERATING" ? "SELL" : "NEUTRAL" });
  }
  if (fr._ema_crossover?.crossed) {
    results.push({ name: "EMA_CROSSOVER", direction: fr._ema_crossover.type === "GOLDEN_CROSS" ? "BUY" : "SELL" });
  }

  return results;
}

// ============================================================
// UL-AWARE ASYMMETRIC SCORING (v2)
// Score each indicator's contribution using UL values
// ============================================================
function calcULScore(
  direction: string,
  analysisSignal: string,
  status: string,
): { wasCorrect: boolean; ulScore: number } {
  const isBuy = analysisSignal === "COMPRA" || analysisSignal === "BUY";
  const isSell = analysisSignal === "VENDA" || analysisSignal === "SELL";
  const isNeutralSignal = !isBuy && !isSell;
  const isWin = status.startsWith("WIN");
  const isLoss = status === "LOSS";

  if (direction === "NEUTRAL") {
    if (isNeutralSignal) {
      return { wasCorrect: true, ulScore: UL_NEUTRAL_CORRECT };
    }
    if (isLoss) {
      // Neutral indicator warned against a LOSS ÔåÆ excellent
      return { wasCorrect: true, ulScore: UL_LOSS_AVOIDED };
    }
    // Neutral indicator but signal was WIN ÔåÆ missed opportunity (graduated by TP level)
    const missedCost = UL_MISSED_COST[status] || -0.3;
    return { wasCorrect: false, ulScore: missedCost };
  }

  // Directional indicator
  const alignedWithSignal = (direction === "BUY" && isBuy) || (direction === "SELL" && isSell);
  const opposedToSignal = (direction === "BUY" && isSell) || (direction === "SELL" && isBuy);

  if (alignedWithSignal) {
    if (isWin) {
      // Aligned + WIN ÔåÆ graduated reward by TP level
      const reward = UL_VALUES[status] || 1.0;
      return { wasCorrect: true, ulScore: reward };
    }
    // Aligned + LOSS ÔåÆ SEVERE penalty (led to a loss)
    return { wasCorrect: false, ulScore: -3.5 };
  }

  if (opposedToSignal) {
    if (isLoss) {
      // Opposed + LOSS ÔåÆ correctly warned against
      return { wasCorrect: true, ulScore: 2.0 };
    }
    // Opposed + WIN ÔåÆ disagreed but trade worked
    const oppCost = -(UL_VALUES[status] || 1.0) * 0.4;
    return { wasCorrect: false, ulScore: oppCost };
  }

  // Neutral signal context with directional indicator
  if (isNeutralSignal) {
    return { wasCorrect: false, ulScore: 0.0 };
  }

  return { wasCorrect: false, ulScore: 0.0 };
}

// ============================================================
// BACKTEST ENGINE: Sweep thresholds to maximize UL
// ============================================================
interface BacktestResult {
  threshold: number;
  ulTotal: number;
  correct: number;
  total: number;
  changes: number;
  lossesAvoided: number;
  totalLosses: number;
  missedOpps: number;
  totalWins: number;
  lossAvoidanceRate: number;
  missedOpportunityRate: number;
  details: any[];
}

function runBacktest(
  allFinalized: any[],
  weightMap: Map<string, number>,
  threshold: number,
): BacktestResult {
  let ulTotal = 0;
  let correct = 0, total = 0, changes = 0;
  let lossesAvoided = 0, totalLosses = 0;
  let missedOpps = 0, totalWins = 0;
  const details: any[] = [];

  for (const hist of allFinalized) {
    const fr = hist.full_result;
    if (!fr) continue;

    const isWin = hist.status?.startsWith("WIN");
    const isLoss = hist.status === "LOSS";
    const originalSignal = hist.signal || fr?.header?.signal || "NEUTRO";
    const originalNormalized = originalSignal === "COMPRA" || originalSignal === "BUY" ? "COMPRA" :
      originalSignal === "VENDA" || originalSignal === "SELL" ? "VENDA" : "NEUTRO";

    if (isLoss) totalLosses++;
    if (isWin && originalNormalized !== "NEUTRO") totalWins++;

    const indicators = extractIndicatorDirections(fr);
    let buyScore = 0, sellScore = 0, totalWeight = 0;

    for (const ind of indicators) {
      const w = weightMap.get(ind.name) ?? DEFAULT_WEIGHTS[ind.name] ?? 1.0;
      totalWeight += w;
      if (ind.direction === "BUY") buyScore += w;
      else if (ind.direction === "SELL") sellScore += w;
    }

    const buyPct = totalWeight > 0 ? (buyScore / totalWeight) * 100 : 50;
    const sellPct = totalWeight > 0 ? (sellScore / totalWeight) * 100 : 50;

    let recalcSignal = "NEUTRO";
    if (buyPct > threshold) recalcSignal = "COMPRA";
    else if (sellPct > threshold) recalcSignal = "VENDA";

    // Calculate UL contribution for this analysis
    let analysisUL = 0;
    const lossAvoided = isLoss && recalcSignal === "NEUTRO" && originalNormalized !== "NEUTRO";
    const missedOpp = isWin && recalcSignal === "NEUTRO" && originalNormalized !== "NEUTRO";

    if (recalcSignal === "NEUTRO") {
      if (isLoss && originalNormalized !== "NEUTRO") {
        // Loss avoided ÔåÆ positive UL
        analysisUL = UL_LOSS_AVOIDED;
        lossesAvoided++;
      } else if (isWin && originalNormalized !== "NEUTRO") {
        // Missed opportunity ÔåÆ negative UL (graduated)
        analysisUL = UL_MISSED_COST[hist.status] || -0.3;
        missedOpps++;
      } else {
        analysisUL = UL_NEUTRAL_CORRECT;
      }
    } else {
      // Actionable signal
      const recalcAligned = (recalcSignal === "COMPRA" && originalNormalized === "COMPRA") ||
                            (recalcSignal === "VENDA" && originalNormalized === "VENDA");
      if (recalcAligned && isWin) {
        analysisUL = UL_VALUES[hist.status] || 1.0;
      } else if (recalcAligned && isLoss) {
        analysisUL = UL_VALUES.LOSS; // -3.0
      } else if (!recalcAligned && isWin) {
        // Recalc flipped direction on a win ÔåÆ bad
        analysisUL = -(UL_VALUES[hist.status] || 1.0) * 0.5;
      } else if (!recalcAligned && isLoss) {
        // Recalc flipped direction on a loss ÔåÆ might have saved it
        analysisUL = UL_LOSS_AVOIDED * 0.5;
      } else {
        analysisUL = 0;
      }
    }

    ulTotal += analysisUL;
    total++;

    // "Correct" = positive UL contribution
    if (analysisUL > 0) correct++;
    if (recalcSignal !== originalNormalized) changes++;

    details.push({
      id: hist.id,
      original_signal: originalNormalized,
      recalc_signal: recalcSignal,
      actual_result: hist.status,
      buy_pct: parseFloat(buyPct.toFixed(1)),
      sell_pct: parseFloat(sellPct.toFixed(1)),
      ul_contribution: parseFloat(analysisUL.toFixed(2)),
      loss_avoided: lossAvoided,
      missed_opportunity: missedOpp,
    });
  }

  const lossAvoidanceRate = totalLosses > 0 ? (lossesAvoided / totalLosses) * 100 : 0;
  const missedOpportunityRate = totalWins > 0 ? (missedOpps / totalWins) * 100 : 0;

  return {
    threshold, ulTotal: parseFloat(ulTotal.toFixed(2)),
    correct, total, changes,
    lossesAvoided, totalLosses,
    missedOpps, totalWins,
    lossAvoidanceRate, missedOpportunityRate,
    details,
  };
}

// ============================================================
// THRESHOLD SWEEP OPTIMIZER
// Finds the threshold that maximizes UL with safety constraints
// ============================================================
function findOptimalThreshold(
  allFinalized: any[],
  weightMap: Map<string, number>,
): { best: BacktestResult; sweep: Array<{ threshold: number; ul: number; lossAvoid: number; missedOpp: number }> } {
  const MIN_THRESHOLD = 42;
  const MAX_THRESHOLD = 72;
  const STEP = 1;
  const MIN_LOSS_AVOIDANCE = 50; // Safety: must avoid at least 50% of losses

  let bestResult: BacktestResult | null = null;
  let bestUL = -Infinity;
  const sweep: Array<{ threshold: number; ul: number; lossAvoid: number; missedOpp: number }> = [];

  for (let t = MIN_THRESHOLD; t <= MAX_THRESHOLD; t += STEP) {
    const result = runBacktest(allFinalized, weightMap, t);
    sweep.push({
      threshold: t,
      ul: result.ulTotal,
      lossAvoid: parseFloat(result.lossAvoidanceRate.toFixed(1)),
      missedOpp: parseFloat(result.missedOpportunityRate.toFixed(1)),
    });

    // Safety constraint: lossAvoidanceRate must be >= 50%
    // (unless there are very few losses where any threshold would fail)
    const passesConstraint = result.totalLosses < 3 || result.lossAvoidanceRate >= MIN_LOSS_AVOIDANCE;

    if (passesConstraint && result.ulTotal > bestUL) {
      bestUL = result.ulTotal;
      bestResult = result;
    }
  }

  // Fallback: if no threshold passes constraint, use the one with highest UL anyway
  if (!bestResult) {
    for (let t = MIN_THRESHOLD; t <= MAX_THRESHOLD; t += STEP) {
      const result = runBacktest(allFinalized, weightMap, t);
      if (result.ulTotal > bestUL) {
        bestUL = result.ulTotal;
        bestResult = result;
      }
    }
  }

  // Anti-stagnation guard
  if (bestResult) {
    if (bestResult.missedOpportunityRate > 60 && bestResult.threshold > MIN_THRESHOLD + 3) {
      // Too conservative: force threshold down
      const adjusted = runBacktest(allFinalized, weightMap, bestResult.threshold - 3);
      console.log(`[AUTO-REFINE] Anti-stagnation: missedOpp ${bestResult.missedOpportunityRate.toFixed(1)}% > 60%, lowering threshold ${bestResult.threshold} ÔåÆ ${adjusted.threshold}`);
      bestResult = adjusted;
    }
    if (bestResult.lossAvoidanceRate < 30 && bestResult.threshold < MAX_THRESHOLD - 3) {
      // Too aggressive: force threshold up
      const adjusted = runBacktest(allFinalized, weightMap, bestResult.threshold + 3);
      console.log(`[AUTO-REFINE] Anti-stagnation: lossAvoid ${bestResult.lossAvoidanceRate.toFixed(1)}% < 30%, raising threshold ${bestResult.threshold} ÔåÆ ${adjusted.threshold}`);
      bestResult = adjusted;
    }
  }

  return { best: bestResult!, sweep };
}

// ============================================================
// MAIN HANDLER
// ============================================================
serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const supabase = createClient(supabaseUrl, serviceRoleKey);

    const body = await req.json().catch(() => ({}));
    const mode = body.mode || "full"; // "extract" | "calibrate" | "full" | "reset"

    console.log(`[AUTO-REFINE] Starting mode: ${mode} | UL-Maximizer v2 | Regra P├®trea: Max UL (evitar LOSS > capturar WIN)`);

    const results: any = { extracted: 0, calibrated: 0, logs: [] };

    // ========== STEP 1: EXTRACT INDICATOR PERFORMANCE ==========
    if (mode === "extract" || mode === "full") {
      const { data: finalizedAnalyses, error: fetchErr } = await supabase
        .from("auto_analysis_history")
        .select("id, asset, timeframe, signal, status, full_result, created_at")
        .in("status", ["WIN_TP1", "WIN_TP2", "WIN_TP3", "WIN", "LOSS"])
        .is("deleted_at", null)
        .order("created_at", { ascending: false })
        .limit(500);

      if (fetchErr) throw new Error(`Fetch error: ${fetchErr.message}`);

      const analysisIds = (finalizedAnalyses || []).map((a: any) => a.id);
      const { data: existingPerf } = await supabase
        .from("indicator_performance")
        .select("analysis_id")
        .in("analysis_id", analysisIds.length > 0 ? analysisIds : ["__none__"]);

      const existingSet = new Set((existingPerf || []).map((p: any) => p.analysis_id));
      const newAnalyses = (finalizedAnalyses || []).filter((a: any) => !existingSet.has(a.id));

      console.log(`[AUTO-REFINE] Found ${finalizedAnalyses?.length || 0} finalized, ${newAnalyses.length} new to extract`);

      for (const analysis of newAnalyses) {
        const fullResult = analysis.full_result;
        if (!fullResult) continue;

        const analysisSignal = analysis.signal || fullResult?.header?.signal || "NEUTRO";
        const indicators = extractIndicatorDirections(fullResult);
        const indicatorRecords: any[] = [];

        for (const ind of indicators) {
          const { wasCorrect } = calcULScore(ind.direction, analysisSignal, analysis.status);

          indicatorRecords.push({
            analysis_id: analysis.id,
            asset: analysis.asset,
            timeframe: analysis.timeframe,
            indicator_name: ind.name,
            direction_suggested: ind.direction,
            weight_used: DEFAULT_WEIGHTS[ind.name] || 1.0,
            actual_result: analysis.status.startsWith("WIN") ? "WIN" : "LOSS",
            was_correct: wasCorrect,
          });
        }

        if (indicatorRecords.length > 0) {
          const { error: insertErr } = await supabase
            .from("indicator_performance")
            .insert(indicatorRecords);
          if (insertErr) {
            console.error(`[AUTO-REFINE] Insert error for ${analysis.id}:`, insertErr.message);
          } else {
            results.extracted += indicatorRecords.length;
          }
        }
      }

      console.log(`[AUTO-REFINE] Extracted ${results.extracted} indicator records from ${newAnalyses.length} analyses`);
    }

    // ========== STEP 2: UL-GRADIENT CALIBRATION ==========
    if (mode === "calibrate" || mode === "full") {
      const { data: combos } = await supabase
        .from("indicator_performance")
        .select("asset, timeframe")
        .limit(1000);

      const uniqueCombos = new Map<string, { asset: string; timeframe: string }>();
      (combos || []).forEach((c: any) => {
        const key = `${c.asset}_${c.timeframe}`;
        if (!uniqueCombos.has(key)) uniqueCombos.set(key, { asset: c.asset, timeframe: c.timeframe });
      });

      for (const [_, combo] of uniqueCombos) {
        const { asset, timeframe } = combo;

        // Get all finalized analyses for backtest
        const { data: allFinalized } = await supabase
          .from("auto_analysis_history")
          .select("id, asset, timeframe, signal, status, full_result, created_at")
          .eq("asset", asset)
          .eq("timeframe", timeframe)
          .in("status", ["WIN_TP1", "WIN_TP2", "WIN_TP3", "WIN", "LOSS"])
          .is("deleted_at", null)
          .limit(500);

        // Get indicator performance with analysis status for UL scoring
        const { data: perfData } = await supabase
          .from("indicator_performance")
          .select("indicator_name, was_correct, weight_used, actual_result, direction_suggested, created_at, analysis_id")
          .eq("asset", asset)
          .eq("timeframe", timeframe);

        if (!perfData || perfData.length < 5) {
          console.log(`[AUTO-REFINE] Skipping ${asset}/${timeframe}: only ${perfData?.length || 0} records (need 5+)`);
          continue;
        }

        // Build analysis status lookup for UL scoring
        const analysisStatusMap = new Map<string, string>();
        (allFinalized || []).forEach((a: any) => analysisStatusMap.set(a.id, a.status));

        // Build analysis signal lookup
        const analysisSignalMap = new Map<string, string>();
        (allFinalized || []).forEach((a: any) => {
          const sig = a.signal || a.full_result?.header?.signal || "NEUTRO";
          analysisSignalMap.set(a.id, sig);
        });

        // ============================================================
        // UL-GRADIENT CALIBRATION per indicator
        // ============================================================
        const indicatorStats = new Map<string, {
          ulContribTotal: number;
          weightedTotal: number;
          rawCorrect: number;
          rawTotal: number;
          losses: number;
          wins: number;
          originalWeight: number;
        }>();

        perfData.forEach((p: any) => {
          const tempWeight = getTemporalWeight(p.created_at);
          const status = analysisStatusMap.get(p.analysis_id) || (p.actual_result === "WIN" ? "WIN_TP1" : "LOSS");
          const signal = analysisSignalMap.get(p.analysis_id) || "NEUTRO";

          const { wasCorrect, ulScore } = calcULScore(p.direction_suggested, signal, status);

          const existing = indicatorStats.get(p.indicator_name) || {
            ulContribTotal: 0, weightedTotal: 0,
            rawCorrect: 0, rawTotal: 0,
            losses: 0, wins: 0,
            originalWeight: p.weight_used || 1,
          };

          existing.ulContribTotal += ulScore * tempWeight;
          existing.weightedTotal += tempWeight;
          existing.rawTotal++;
          if (wasCorrect) existing.rawCorrect++;
          if (p.actual_result === "LOSS") existing.losses++;
          if (p.actual_result === "WIN") existing.wins++;

          indicatorStats.set(p.indicator_name, existing);
        });

        // Overall WR before
        const totalCorrect = perfData.filter((p: any) => p.was_correct).length;
        const overallWRBefore = (totalCorrect / perfData.length) * 100;

        const adjustments: any[] = [];
        const upsertRows: any[] = [];

        for (const [indicatorName, stats] of indicatorStats) {
          const rawWr = stats.rawTotal > 0 ? (stats.rawCorrect / stats.rawTotal) * 100 : 50;
          const originalWeight = DEFAULT_WEIGHTS[indicatorName] || stats.originalWeight || 1.0;

          // UL Contribution per participation (normalized)
          const ulContrib = stats.weightedTotal > 0 ? stats.ulContribTotal / stats.weightedTotal : 0;

          let calibratedWeight = originalWeight;
          let trend = "STABLE";

          // Minimum 5 samples to calibrate
          if (stats.rawTotal >= 5) {
            // KILL SWITCH: if UL_contrib < -2.0 with 5+ loss participations ÔåÆ silence
            if (ulContrib < -2.0 && stats.losses >= 5) {
              calibratedWeight = 0.05;
              trend = "KILLED";
              adjustments.push({
                indicator: indicatorName, action: "KILL",
                wr: rawWr.toFixed(1), ul_contrib: ulContrib.toFixed(3),
                losses: stats.losses,
                from: originalWeight, to: 0.05,
                samples: stats.rawTotal,
              });
            } else if (ulContrib > 0.5) {
              // Strong positive UL ÔåÆ boost (up to 1.4x original, cap at 4.0)
              const boostFactor = 1.0 + Math.min(0.4, (ulContrib - 0.5) * 0.3);
              calibratedWeight = Math.min(originalWeight * boostFactor, Math.min(originalWeight * 2.0, 4.0));
              trend = "IMPROVING";
              adjustments.push({
                indicator: indicatorName, action: "BOOST",
                wr: rawWr.toFixed(1), ul_contrib: ulContrib.toFixed(3),
                from: originalWeight, to: parseFloat(calibratedWeight.toFixed(2)),
                samples: stats.rawTotal,
              });
            } else if (ulContrib < -0.3) {
              // Negative UL ÔåÆ reduce proportionally (floor at 0.1)
              const reduceFactor = Math.max(0.15, 1.0 + (ulContrib * 0.5));
              calibratedWeight = Math.max(originalWeight * reduceFactor, 0.1);
              trend = "DEGRADING";
              adjustments.push({
                indicator: indicatorName, action: "REDUCE",
                wr: rawWr.toFixed(1), ul_contrib: ulContrib.toFixed(3),
                from: originalWeight, to: parseFloat(calibratedWeight.toFixed(2)),
                samples: stats.rawTotal,
              });
            }
            // Between -0.3 and 0.5: stable
          }

          upsertRows.push({
            asset,
            timeframe,
            indicator_name: indicatorName,
            original_weight: originalWeight,
            calibrated_weight: parseFloat(calibratedWeight.toFixed(4)),
            win_rate: parseFloat(rawWr.toFixed(2)),
            sample_count: stats.rawTotal,
            trend,
            last_calibrated_at: new Date().toISOString(),
          });
        }

        // Upsert refinement weights
        if (upsertRows.length > 0) {
          const { error: upsertErr } = await supabase
            .from("refinement_weights")
            .upsert(upsertRows, { onConflict: "asset,timeframe,indicator_name" });
          if (upsertErr) {
            console.error(`[AUTO-REFINE] Upsert error for ${asset}/${timeframe}:`, upsertErr.message);
          } else {
            results.calibrated += upsertRows.length;
          }
        }

        // ========== THRESHOLD SWEEP OPTIMIZER ==========
        const newWeightMap = new Map<string, number>();
        upsertRows.forEach((r: any) => newWeightMap.set(r.indicator_name, r.calibrated_weight));

        const allFinalizedArr = allFinalized || [];
        if (allFinalizedArr.length >= 3) {
          const { best, sweep } = findOptimalThreshold(allFinalizedArr, newWeightMap);

          const projectedWR = best.total > 0 ? (best.correct / best.total) * 100 : null;

          // Log calibration run
          const { error: logErr } = await supabase
            .from("refinement_log")
            .insert({
              asset,
              timeframe,
              overall_wr_before: parseFloat(overallWRBefore.toFixed(2)),
              overall_wr_after: projectedWR !== null ? parseFloat(projectedWR.toFixed(2)) : parseFloat(overallWRBefore.toFixed(2)),
              indicators_adjusted: adjustments.length,
              adjustments_json: adjustments,
              analysis_count: perfData.length,
              projected_wr_new_weights: projectedWR !== null ? parseFloat(projectedWR.toFixed(2)) : null,
              backtest_signal_changes: best.changes,
              backtest_details: best.details.length > 0 ? best.details : null,
              loss_avoidance_rate: parseFloat(best.lossAvoidanceRate.toFixed(2)),
              missed_opportunity_rate: parseFloat(best.missedOpportunityRate.toFixed(2)),
              effective_threshold: best.threshold,
            });

          if (logErr) console.error(`[AUTO-REFINE] Log error:`, logErr.message);

          results.logs.push({
            asset, timeframe,
            totalIndicators: upsertRows.length,
            adjusted: adjustments.length,
            overallWR: overallWRBefore.toFixed(1),
            projectedWR: projectedWR?.toFixed(1) || "N/A",
            ulTotal: best.ulTotal,
            optimalThreshold: best.threshold,
            signalChanges: best.changes,
            lossAvoidanceRate: best.lossAvoidanceRate.toFixed(1),
            missedOpportunityRate: best.missedOpportunityRate.toFixed(1),
            backtestSamples: best.total,
            samples: perfData.length,
            thresholdSweep: sweep,
          });

          console.log(`[AUTO-REFINE] Ô£à ${asset}/${timeframe}: UL=${best.ulTotal} | WR ${overallWRBefore.toFixed(1)}% ÔåÆ ${projectedWR?.toFixed(1) || "N/A"}% | Threshold: ${best.threshold}% | LossAvoid: ${best.lossAvoidanceRate.toFixed(1)}% | MissedOpp: ${best.missedOpportunityRate.toFixed(1)}% | ${best.changes} changes`);
        } else {
          console.log(`[AUTO-REFINE] Skipping backtest for ${asset}/${timeframe}: only ${allFinalizedArr.length} finalized (need 3+)`);
        }
      }
    }

    // ========== RESET MODE ==========
    if (mode === "reset") {
      await supabase.from("refinement_weights").delete().neq("id", "00000000-0000-0000-0000-000000000000");
      await supabase.from("indicator_performance").delete().neq("id", "00000000-0000-0000-0000-000000000000");
      results.logs.push({ action: "RESET", message: "All refinement data cleared" });
      console.log(`[AUTO-REFINE] Reset complete`);
    }

    console.log(`[AUTO-REFINE] Done. Extracted: ${results.extracted}, Calibrated: ${results.calibrated}`);

    return new Response(JSON.stringify({ success: true, ...results }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (err) {
    console.error("[AUTO-REFINE] Fatal error:", err);
    return new Response(JSON.stringify({ error: String(err) }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.3";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version",
};

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const authHeader = req.headers.get("authorization");
    if (!authHeader) {
      return new Response(JSON.stringify({ error: "Not authenticated" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const supabaseKey = Deno.env.get("SUPABASE_ANON_KEY")!;
    const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;

    const supabase = createClient(supabaseUrl, supabaseKey, {
      global: { headers: { Authorization: authHeader } },
    });

    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser();
    if (authError || !user) {
      return new Response(JSON.stringify({ error: "Invalid token" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const { assets, timeframe } = await req.json();

    // 1. Get user's autopilot settings
    const { data: settings } = await supabase
      .from("autopilot_settings")
      .select("*")
      .eq("user_id", user.id)
      .single();

    if (!settings?.is_active) {
      return new Response(
        JSON.stringify({ executed: false, reason: "Autopilot is not active" }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // 2. Get broker credentials
    const { data: creds } = await supabase
      .from("broker_credentials")
      .select("api_key, api_secret, broker, is_connected")
      .eq("user_id", user.id)
      .single();

    if (!creds?.is_connected) {
      return new Response(
        JSON.stringify({ executed: false, reason: "Broker not connected" }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // 3. Run analysis on each asset via the analyze-asset function internally
    const analyzeUrl = `${supabaseUrl}/functions/v1/analyze-asset`;
    const results: any[] = [];
    const targetAssets = assets || ["BTCUSDT", "ETHUSDT", "SOLUSDT"];

    for (const asset of targetAssets) {
      try {
        console.log(`[AUTOTRADE] Analyzing ${asset}/${timeframe || "1h"}...`);

        const analysisRes = await fetch(analyzeUrl, {
          method: "POST",
          headers: {
            Authorization: authHeader,
            apikey: supabaseKey,
            "Content-Type": "application/json",
          },
          body: JSON.stringify({ asset, timeframe: timeframe || "1h" }),
        });

        if (!analysisRes.ok) {
          const errText = await analysisRes.text();
          console.error(`[AUTOTRADE] Analysis failed for ${asset}: ${errText}`);
          continue;
        }

        const analysis = await analysisRes.json();

        // 4. Check if signal is strong enough to execute
        const confidence = analysis?.header?.final_confidence_pct || 0;
        const signal = analysis?.header?.signal;
        const signalStrength = analysis?.header?.signal_strength_pct || 0;

        console.log(
          `[AUTOTRADE] ${asset}: Signal=${signal}, Confidence=${confidence}%, Strength=${signalStrength}%`
        );

        // Only execute on high-confidence signals
        if (confidence < 75 || signal === "NEUTRO") {
          results.push({
            asset,
            signal,
            confidence,
            executed: false,
            reason: `Confidence ${confidence}% below 75% threshold or neutral signal`,
          });
          continue;
        }

        // 5. Calculate position size
        const accountRes = await fetch(
          `${supabaseUrl}/functions/v1/binance-proxy`,
          {
            method: "POST",
            headers: {
              Authorization: authHeader,
              apikey: supabaseKey,
              "Content-Type": "application/json",
            },
            body: JSON.stringify({ action: "account_info" }),
          }
        );

        if (!accountRes.ok) {
          const errText = await accountRes.text();
          console.error(`[AUTOTRADE] Account info failed: ${errText}`);
          continue;
        }

        const account = await accountRes.json();
        const balance = account.availableBalance || 0;
        const riskPct = Number(settings.risk_pct) || 2;
        const maxLeverage = settings.max_leverage || 10;

        // Daily PnL check (kill switch)
        const profitGoal = Number(settings.profit_goal) || 200;
        const maxLoss = Number(settings.max_loss) || 100;
        const dailyPnl = account.totalPnl || 0;

        if (dailyPnl >= profitGoal) {
          // Deactivate autopilot
          const adminClient = createClient(supabaseUrl, serviceKey);
          await adminClient
            .from("autopilot_settings")
            .update({
              is_active: false,
              deactivation_reason: `daily_profit_goal_reached: +$${dailyPnl.toFixed(2)}`,
            })
            .eq("user_id", user.id);

          return new Response(
            JSON.stringify({
              executed: false,
              reason: `Daily profit goal reached (+$${dailyPnl.toFixed(2)}). Autopilot deactivated.`,
              autopilot_deactivated: true,
            }),
            { headers: { ...corsHeaders, "Content-Type": "application/json" } }
          );
        }

        if (dailyPnl <= -maxLoss) {
          const adminClient = createClient(supabaseUrl, serviceKey);
          await adminClient
            .from("autopilot_settings")
            .update({
              is_active: false,
              deactivation_reason: `daily_loss_limit_reached: -$${Math.abs(dailyPnl).toFixed(2)}`,
            })
            .eq("user_id", user.id);

          return new Response(
            JSON.stringify({
              executed: false,
              reason: `Daily loss limit reached (-$${Math.abs(dailyPnl).toFixed(2)}). Autopilot deactivated.`,
              autopilot_deactivated: true,
            }),
            { headers: { ...corsHeaders, "Content-Type": "application/json" } }
          );
        }

        // Position sizing
        const entryPrice = analysis?.risk_management?.entry_price || 0;
        const stopLoss = analysis?.risk_management?.stop_loss || 0;
        const tp1 = analysis?.risk_management?.take_profit_1 || 0;

        if (!entryPrice || !stopLoss || !tp1) {
          results.push({
            asset,
            signal,
            confidence,
            executed: false,
            reason: "Missing entry/SL/TP from analysis",
          });
          continue;
        }

        const riskAmount = balance * (riskPct / 100);
        const stopDistance =
          Math.abs(entryPrice - stopLoss) / entryPrice;
        if (stopDistance === 0) continue;

        const positionSizeUSD = riskAmount / stopDistance;
        const leverage = Math.min(
          maxLeverage,
          Math.floor(positionSizeUSD / balance)
        );
        const actualLeverage = Math.max(1, Math.min(leverage, maxLeverage));
        const quantity = (riskAmount / stopDistance) / entryPrice;

        // Round quantity to Binance precision (simplified)
        const symbol = asset.includes("/")
          ? asset.replace("/", "")
          : asset;
        let quantityPrecision = 3;
        if (symbol.includes("BTC")) quantityPrecision = 3;
        else if (symbol.includes("ETH")) quantityPrecision = 3;
        else quantityPrecision = 1;

        const roundedQty = parseFloat(
          quantity.toFixed(quantityPrecision)
        );

        if (roundedQty <= 0) {
          results.push({
            asset,
            signal,
            confidence,
            executed: false,
            reason: "Calculated quantity is 0",
          });
          continue;
        }

        const side = signal === "COMPRA" ? "BUY" : "SELL";

        // 6. Execute via binance-proxy
        console.log(
          `[AUTOTRADE] EXECUTING: ${side} ${roundedQty} ${symbol} @ market, SL=$${stopLoss}, TP=$${tp1}, Leverage=${actualLeverage}x`
        );

        const proxyUrl = `${supabaseUrl}/functions/v1/binance-proxy`;

        // Set leverage
        await fetch(proxyUrl, {
          method: "POST",
          headers: {
            Authorization: authHeader,
            apikey: supabaseKey,
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            action: "set_leverage",
            symbol,
            leverage: actualLeverage,
          }),
        });

        // Place market entry order
        const entryRes = await fetch(proxyUrl, {
          method: "POST",
          headers: {
            Authorization: authHeader,
            apikey: supabaseKey,
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            action: "place_order",
            symbol,
            side,
            type: "MARKET",
            quantity: roundedQty,
          }),
        });
        const entryResult = await entryRes.json();

        if (entryResult.error) {
          results.push({
            asset,
            signal,
            confidence,
            executed: false,
            reason: `Order failed: ${entryResult.error}`,
          });
          continue;
        }

        // Place Stop Loss
        const slSide = side === "BUY" ? "SELL" : "BUY";
        await fetch(proxyUrl, {
          method: "POST",
          headers: {
            Authorization: authHeader,
            apikey: supabaseKey,
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            action: "place_order",
            symbol,
            side: slSide,
            type: "STOP_MARKET",
            quantity: roundedQty,
            stopPrice: stopLoss,
            reduceOnly: true,
          }),
        });

        // Place Take Profit
        await fetch(proxyUrl, {
          method: "POST",
          headers: {
            Authorization: authHeader,
            apikey: supabaseKey,
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            action: "place_order",
            symbol,
            side: slSide,
            type: "TAKE_PROFIT_MARKET",
            quantity: roundedQty,
            stopPrice: tp1,
            reduceOnly: true,
          }),
        });

        // 7. Save to analysis_history
        const { data: historyRecord } = await supabase.from("analysis_history").insert({
          user_id: user.id,
          asset,
          timeframe: timeframe || "1h",
          signal: analysis.header.signal,
          signal_strength_pct: signalStrength,
          final_confidence_pct: confidence,
          trend: analysis.header.trend,
          entry_price: entryPrice,
          stop_loss: stopLoss,
          take_profit_1: tp1,
          take_profit_2: analysis?.risk_management?.take_profit_2,
          take_profit_3: analysis?.risk_management?.take_profit_3,
          risk_reward_ratio: analysis?.risk_management?.risk_reward_ratio,
          executive_summary: `[AUTOTRADE] ${analysis?.institutional_synthesis?.executive_summary || ""}`,
          data_source: analysis?._data_source,
          full_result: analysis,
        }).select().single();

        // 8. Create trade_positions record (state machine)
        const tp2 = analysis?.risk_management?.take_profit_2;
        const tp3 = analysis?.risk_management?.take_profit_3;
        const positionSide = side === "BUY" ? "LONG" : "SHORT";
        // True Breakeven: entry ┬▒ 0.12% (open fee + close fee + slippage buffer)
        const trueBreakeven = positionSide === "LONG"
          ? entryPrice * (1 + 0.0012)
          : entryPrice * (1 - 0.0012);
        const partialSize = parseFloat((roundedQty * 0.3333).toFixed(8));

        await supabase.from("trade_positions").insert({
          user_id: user.id,
          analysis_id: historyRecord?.id || null,
          symbol,
          side: positionSide,
          trade_state: "ACTIVE",
          original_size: roundedQty,
          total_position_size: roundedQty,
          current_avg_price: entryPrice,
          true_breakeven_price: trueBreakeven,
          accumulated_fees: roundedQty * entryPrice * 0.0005,
          partial_size: partialSize,
          entry_price: entryPrice,
          stop_loss_original: stopLoss,
          stop_loss_current: stopLoss,
          take_profit_1: tp1,
          take_profit_2: tp2 || null,
          take_profit_3: tp3 || null,
          leverage: actualLeverage,
          risk_pct: riskPct,
          entry_order_id: entryResult.orderId?.toString() || null,
          dca_history: [{ price: entryPrice, qty: roundedQty, time: new Date().toISOString() }],
        });

        results.push({
          asset,
          signal,
          confidence,
          executed: true,
          side,
          quantity: roundedQty,
          leverage: actualLeverage,
          stopLoss,
          takeProfit: tp1,
          orderId: entryResult.orderId,
        });
      } catch (assetError) {
        console.error(`[AUTOTRADE] Error processing ${asset}:`, assetError);
        results.push({
          asset,
          executed: false,
          reason:
            assetError instanceof Error
              ? assetError.message
              : "Unknown error",
        });
      }
    }

    return new Response(JSON.stringify({ results, timestamp: Date.now() }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (error) {
    console.error("autotrade-engine error:", error);
    return new Response(
      JSON.stringify({
        error: error instanceof Error ? error.message : "Unknown error",
      }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.39.3";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version",
};

const BINANCE_MAINNET = "https://fapi.binance.com";
const BINANCE_TESTNET = "https://testnet.binancefuture.com";

class BinanceApiError extends Error {
  code: number | string;
  status: number;

  constructor(code: number | string, message: string, status: number) {
    super(message);
    this.name = "BinanceApiError";
    this.code = code;
    this.status = status;
  }
}

function jsonResponse(body: unknown, status = 200) {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

function formatBinanceError(
  code: number | string,
  message: string,
  isTestnet: boolean
): string {
  const base = `Binance [${code}]: ${message}`;

  if (Number(code) === -2015) {
    return `${base}\n\nChecklist: 1) Ative permiss├úo de Futures na chave. 2) Use chave do ambiente correto (${isTestnet ? "Testnet" : "Mainnet"}). 3) Em infraestrutura cloud sem IP fixo, n├úo restrinja por IP. 4) Gere nova chave se mudou permiss├Áes recentemente.`;
  }

  if (Number(code) === -1021) {
    return `${base}\n\nO rel├│gio da requisi├º├úo est├í fora da janela permitida. Tente novamente em alguns segundos.`;
  }

  if (Number(code) === -1022) {
    return `${base}\n\nAssinatura inv├ílida. Revise API Secret e remova espa├ºos extras no in├¡cio/fim.`;
  }

  return base;
}

async function hmacSign(secret: string, message: string): Promise<string> {
  const enc = new TextEncoder();
  const key = await crypto.subtle.importKey(
    "raw",
    enc.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );
  const sig = await crypto.subtle.sign("HMAC", key, enc.encode(message));
  return Array.from(new Uint8Array(sig))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

async function binanceRequest(
  baseUrl: string,
  apiKey: string,
  apiSecret: string,
  method: string,
  endpoint: string,
  params: Record<string, string> = {}
): Promise<any> {
  params.timestamp = Date.now().toString();
  params.recvWindow = "10000";

  const queryString = Object.entries(params)
    .map(([k, v]) => `${k}=${encodeURIComponent(v)}`)
    .join("&");

  const signature = await hmacSign(apiSecret, queryString);
  const url = `${baseUrl}${endpoint}?${queryString}&signature=${signature}`;

  console.log(`[binance-proxy] ${method} ${baseUrl}${endpoint}`);

  const response = await fetch(url, {
    method,
    headers: {
      "X-MBX-APIKEY": apiKey,
      "Content-Type": "application/x-www-form-urlencoded",
    },
  });

  const rawBody = await response.text();
  let data: any = {};

  try {
    data = rawBody ? JSON.parse(rawBody) : {};
  } catch {
    data = { msg: rawBody || "Resposta n├úo-JSON da Binance" };
  }

  if (!response.ok) {
    const binanceMsg = data?.msg || JSON.stringify(data);
    const binanceCode = data?.code ?? response.status;
    throw new BinanceApiError(binanceCode, binanceMsg, response.status);
  }

  return data;
}

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  let currentIsTestnet = true;

  try {
    // 1) Session token (JWT) is used ONLY for app authentication
    const authHeader = req.headers.get("authorization");
    if (!authHeader?.startsWith("Bearer ")) {
      console.error("[binance-proxy] Missing or invalid authorization header");
      return jsonResponse({ error: "N├úo autenticado. Fa├ºa login novamente." }, 401);
    }

    const token = authHeader.replace("Bearer ", "").trim();
    if (!token) {
      return jsonResponse({ error: "Token inv├ílido. Fa├ºa login novamente." }, 401);
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL");
    const supabaseKey = Deno.env.get("SUPABASE_ANON_KEY");

    if (!supabaseUrl || !supabaseKey) {
      console.error("[binance-proxy] Missing SUPABASE_URL or SUPABASE_ANON_KEY");
      return jsonResponse({ error: "Configura├º├úo do servidor incompleta." }, 500);
    }

    // 2) Validate JWT claims
    const supabase = createClient(supabaseUrl, supabaseKey, {
      global: { headers: { Authorization: authHeader } },
    });

    const { data: { user }, error: claimsError } = await supabase.auth.getUser(token);

    if (claimsError || !user?.id) {
      console.error("[binance-proxy] JWT verification failed:", claimsError?.message);
      return jsonResponse({ error: "Token inv├ílido. Fa├ºa login novamente." }, 401);
    }

    const userId = user.id;
    console.log(`[binance-proxy] Authenticated user: ${userId}`);

    // 3) Parse body
    let body: any;
    try {
      body = await req.json();
    } catch {
      return jsonResponse({ error: "Corpo da requisi├º├úo inv├ílido." }, 400);
    }

    const {
      action,
      apiKey: _ignoredBodyApiKey,
      apiSecret: _ignoredBodyApiSecret,
      ...actionParams
    } = body || {};

    if (_ignoredBodyApiKey || _ignoredBodyApiSecret) {
      console.warn("[binance-proxy] Ignoring apiKey/apiSecret sent in request body. Using stored broker credentials only.");
    }

    if (!action || typeof action !== "string") {
      return jsonResponse({ error: "A├º├úo n├úo especificada ou inv├ílida." }, 400);
    }

    console.log(`[binance-proxy] Action: ${action}`);

    // 4) Fetch broker credentials from backend storage
    const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
    if (!serviceKey) {
      console.error("[binance-proxy] Missing SUPABASE_SERVICE_ROLE_KEY");
      return jsonResponse({ error: "Configura├º├úo do servidor incompleta." }, 500);
    }

    const adminClient = createClient(supabaseUrl, serviceKey);
    const { data: creds, error: credsError } = await adminClient
      .from("broker_credentials")
      .select("api_key, api_secret, broker, is_testnet")
      .eq("user_id", userId)
      .maybeSingle();

    if (credsError) {
      console.error("[binance-proxy] Credentials query error:", credsError.message);
      return jsonResponse({ error: `Erro ao buscar credenciais: ${credsError.message}` }, 500);
    }

    if (!creds) {
      console.error("[binance-proxy] No credentials found for user:", userId);
      return jsonResponse({ error: "Nenhuma credencial encontrada. Conecte sua corretora primeiro." }, 400);
    }

    if (!creds.api_key || !creds.api_secret) {
      return jsonResponse({ error: "Credenciais incompletas. Insira API Key e Secret." }, 400);
    }

    currentIsTestnet = Boolean(creds.is_testnet);
    const baseUrl = currentIsTestnet ? BINANCE_TESTNET : BINANCE_MAINNET;
    const maskedKey = `${creds.api_key.slice(0, 6)}...${creds.api_key.slice(-4)}`;

    console.log(`[binance-proxy] Using ${currentIsTestnet ? "TESTNET" : "MAINNET"}: ${baseUrl}`);
    console.log(`[binance-proxy] Broker key prefix: ${maskedKey}`);

    // 5) Execute action against Binance Futures endpoints only (/fapi/...)
    let result: any;

    switch (action) {
      case "account_info": {
        result = await binanceRequest(baseUrl, creds.api_key, creds.api_secret, "GET", "/fapi/v2/account");
        const balance = result.totalWalletBalance ? parseFloat(result.totalWalletBalance) : 0;
        const available = result.availableBalance ? parseFloat(result.availableBalance) : 0;
        const unrealizedPnl = result.totalUnrealizedProfit ? parseFloat(result.totalUnrealizedProfit) : 0;
        result = {
          connected: true,
          pingMs: 0,
          accountBalance: balance,
          availableBalance: available,
          totalPnl: unrealizedPnl,
          totalMarginBalance: result.totalMarginBalance ? parseFloat(result.totalMarginBalance) : 0,
        };
        break;
      }

      case "positions": {
        const positions = await binanceRequest(baseUrl, creds.api_key, creds.api_secret, "GET", "/fapi/v2/positionRisk");
        result = positions
          .filter((p: any) => parseFloat(p.positionAmt) !== 0)
          .map((p: any) => ({
            id: `${p.symbol}-${p.positionSide}`,
            symbol: p.symbol.replace("USDT", "/USDT"),
            side: parseFloat(p.positionAmt) > 0 ? "LONG" : "SHORT",
            size: Math.abs(parseFloat(p.positionAmt)),
            entryPrice: parseFloat(p.entryPrice),
            currentPrice: parseFloat(p.markPrice),
            pnl: parseFloat(p.unRealizedProfit),
            roe:
              parseFloat(p.entryPrice) > 0
                ? ((parseFloat(p.markPrice) - parseFloat(p.entryPrice)) /
                    parseFloat(p.entryPrice)) *
                  parseFloat(p.leverage) *
                  100 *
                  (parseFloat(p.positionAmt) > 0 ? 1 : -1)
                : 0,
            stopLoss: 0,
            takeProfit: 0,
            leverage: parseInt(p.leverage),
            trailingActive: false,
            breakEven: false,
            timestamp: Date.now(),
            liquidationPrice: parseFloat(p.liquidationPrice),
          }));
        break;
      }

      case "open_orders": {
        result = await binanceRequest(
          baseUrl,
          creds.api_key,
          creds.api_secret,
          "GET",
          "/fapi/v1/openOrders",
          actionParams.symbol ? { symbol: String(actionParams.symbol) } : {}
        );
        break;
      }

      case "place_order": {
        const { symbol, side, type, quantity, price, stopPrice, reduceOnly, leverage } = actionParams;

        if (!symbol || !side || !type || quantity === undefined || quantity === null) {
          return jsonResponse(
            { error: "Par├ómetros obrigat├│rios ausentes para place_order (symbol, side, type, quantity)." },
            400
          );
        }

        const numericQty = Number(quantity);
        if (!Number.isFinite(numericQty) || numericQty <= 0) {
          return jsonResponse({ error: "Quantidade inv├ílida para place_order." }, 400);
        }

        if (leverage !== undefined && leverage !== null) {
          await binanceRequest(baseUrl, creds.api_key, creds.api_secret, "POST", "/fapi/v1/leverage", {
            symbol: String(symbol),
            leverage: Number(leverage).toString(),
          });
        }

        const orderParams: Record<string, string> = {
          symbol: String(symbol),
          side: String(side),
          type: String(type),
          quantity: numericQty.toString(),
        };

        if (price !== undefined && price !== null) orderParams.price = Number(price).toString();
        if (stopPrice !== undefined && stopPrice !== null) orderParams.stopPrice = Number(stopPrice).toString();
        if (reduceOnly) orderParams.reduceOnly = "true";
        if (String(type) === "LIMIT") orderParams.timeInForce = "GTC";

        result = await binanceRequest(baseUrl, creds.api_key, creds.api_secret, "POST", "/fapi/v1/order", orderParams);
        break;
      }

      case "cancel_order": {
        if (!actionParams.symbol || !actionParams.orderId) {
          return jsonResponse({ error: "Par├ómetros obrigat├│rios ausentes para cancel_order (symbol, orderId)." }, 400);
        }
        result = await binanceRequest(baseUrl, creds.api_key, creds.api_secret, "DELETE", "/fapi/v1/order", {
          symbol: String(actionParams.symbol),
          orderId: String(actionParams.orderId),
        });
        break;
      }

      case "cancel_all": {
        if (actionParams.symbol) {
          result = await binanceRequest(
            baseUrl,
            creds.api_key,
            creds.api_secret,
            "DELETE",
            "/fapi/v1/allOpenOrders",
            { symbol: String(actionParams.symbol) }
          );
        } else {
          const positions = await binanceRequest(baseUrl, creds.api_key, creds.api_secret, "GET", "/fapi/v2/positionRisk");
          const activePositions = positions.filter((p: any) => parseFloat(p.positionAmt) !== 0);
          const closeResults = [];

          for (const pos of activePositions) {
            const amt = parseFloat(pos.positionAmt);
            const closeSide = amt > 0 ? "SELL" : "BUY";
            try {
              const closeResult = await binanceRequest(baseUrl, creds.api_key, creds.api_secret, "POST", "/fapi/v1/order", {
                symbol: pos.symbol,
                side: closeSide,
                type: "MARKET",
                quantity: Math.abs(amt).toString(),
                reduceOnly: "true",
              });
              closeResults.push(closeResult);
            } catch (e) {
              const msg = e instanceof Error ? e.message : "Erro ao fechar posi├º├úo";
              closeResults.push({ error: msg, symbol: pos.symbol });
            }
          }

          result = { closed: closeResults.length, details: closeResults };
        }
        break;
      }

      case "set_leverage": {
        if (!actionParams.symbol || actionParams.leverage === undefined || actionParams.leverage === null) {
          return jsonResponse({ error: "Par├ómetros obrigat├│rios ausentes para set_leverage (symbol, leverage)." }, 400);
        }
        result = await binanceRequest(baseUrl, creds.api_key, creds.api_secret, "POST", "/fapi/v1/leverage", {
          symbol: String(actionParams.symbol),
          leverage: Number(actionParams.leverage).toString(),
        });
        break;
      }

      default:
        return jsonResponse({ error: `A├º├úo desconhecida: ${action}` }, 400);
    }

    console.log(`[binance-proxy] Action ${action} completed successfully`);
    return jsonResponse(result);
  } catch (error) {
    if (error instanceof BinanceApiError) {
      const friendlyMessage = formatBinanceError(error.code, error.message, currentIsTestnet);
      console.error("[binance-proxy] Binance error:", friendlyMessage);
      return jsonResponse({ error: friendlyMessage, binance_code: error.code }, 400);
    }

    const msg = error instanceof Error ? error.message : "Erro desconhecido";
    console.error("[binance-proxy] Error:", msg);
    return jsonResponse({ error: msg }, 500);
  }
});

