  RSI: 1.5, STOCH: 1.0, BOLL: 1.0, CCI: 1.0, WILLIAMS_R: 1.0, AO: 1.0, MOMENTUM: 1.0, STOCH_RSI: 1.0, BULL_BEAR: 1.0, ULT_OSC: 1.0,
  OPEN_INTEREST: 1.5, FEAR_GREED: 1.5, FUNDING_RATE: 1.0, MC_REGIME: 1.5,
  FIB_PROXIMITY: 1.5, DIV_RSI: 2.5, DIV_MACD: 2.5,
  DOJI: 1.0, HAMMER: 1.0, SHOOTING_STAR: 1.0, BULLISH_ENGULFING: 2.0, BEARISH_ENGULFING: 2.0, MORNING_STAR: 2.0, EVENING_STAR: 2.0,
};

// ============================================================
// TEMPORAL DECAY: Recent data matters more
// ============================================================
function getTemporalWeight(createdAt: string): number {
  const ageMs = Date.now() - new Date(createdAt).getTime();
  const ageDays = ageMs / (1000 * 60 * 60 * 24);
  if (ageDays <= 7) return 1.0;
  if (ageDays <= 30) return 0.7;
  if (ageDays <= 90) return 0.4;
  return 0.2;
}

// ============================================================
// INDICATOR DIRECTION EXTRACTION (shared logic)
// ============================================================
function extractIndicatorDirections(fr: any): Array<{ name: string; direction: string }> {
  const results: Array<{ name: string; direction: string }> = [];
  const ti = fr.technical_indicators || {};
  const entryP = fr.risk_management?.entry_price || 0;

  if (ti.rsi) {
    const dir = ti.rsi.value > 70 ? "SELL" : ti.rsi.value < 30 ? "BUY" : "NEUTRAL";
    results.push({ name: "RSI", direction: dir });
  }
  if (ti.macd) {
    results.push({ name: "MACD_HIST", direction: ti.macd.histogram > 0 ? "BUY" : ti.macd.histogram < 0 ? "SELL" : "NEUTRAL" });
    results.push({ name: "MACD_LINE", direction: ti.macd.value > ti.macd.signal_line ? "BUY" : "SELL" });
  }
  if (ti.adx && ti.adx.value > 20) {
    const signal = fr.header?.signal || "NEUTRO";
    const isBuy = signal === "COMPRA" || signal === "BUY";
    const isSell = signal === "VENDA" || signal === "SELL";
    results.push({ name: "ADX_DIR", direction: isBuy ? "BUY" : isSell ? "SELL" : "NEUTRAL" });
  }
  if (ti.stochastic) {
    results.push({ name: "STOCH", direction: ti.stochastic.k < 30 ? "BUY" : ti.stochastic.k > 70 ? "SELL" : "NEUTRAL" });
  }
  if (ti.bollinger && entryP) {
    results.push({ name: "BOLL", direction: entryP < ti.bollinger.lower ? "BUY" : entryP > ti.bollinger.upper ? "SELL" : "NEUTRAL" });
  }
  if (ti.cci !== undefined) {
    results.push({ name: "CCI", direction: ti.cci < -100 ? "BUY" : ti.cci > 100 ? "SELL" : "NEUTRAL" });
  }
  if (ti.mfi !== undefined) {
    results.push({ name: "MFI", direction: ti.mfi < 20 ? "BUY" : ti.mfi > 80 ? "SELL" : "NEUTRAL" });
  }
  if (ti.ichimoku) {
    results.push({ name: "ICHIMOKU", direction: ti.ichimoku.signal === "BULLISH" ? "BUY" : ti.ichimoku.signal === "BEARISH" ? "SELL" : "NEUTRAL" });
  }
  if (ti.vwap && entryP) {
    results.push({ name: "VWAP", direction: entryP > ti.vwap * 1.001 ? "BUY" : entryP < ti.vwap * 0.999 ? "SELL" : "NEUTRAL" });
  }
  if (ti.ema_20 && ti.ema_50 && ti.ema_200) {
    if (ti.ema_20 > ti.ema_50 && ti.ema_50 > ti.ema_200) results.push({ name: "EMA_ALIGNMENT", direction: "BUY" });
    else if (ti.ema_20 < ti.ema_50 && ti.ema_50 < ti.ema_200) results.push({ name: "EMA_ALIGNMENT", direction: "SELL" });
    else results.push({ name: "EMA_ALIGNMENT", direction: "NEUTRAL" });
    results.push({ name: "EMA20", direction: entryP > ti.ema_20 ? "BUY" : "SELL" });
    results.push({ name: "EMA50", direction: entryP > ti.ema_50 ? "BUY" : "SELL" });
    results.push({ name: "EMA200", direction: entryP > ti.ema_200 ? "BUY" : "SELL" });
  }
  if (fr._obv_slope) {
    results.push({ name: "OBV_SLOPE", direction: fr._obv_slope.obvTrend === "ACCUMULATION" ? "BUY" : fr._obv_slope.obvTrend === "DISTRIBUTION" ? "SELL" : "NEUTRAL" });
  }
  if (fr._volume_delta) {
    results.push({ name: "VOL_DELTA", direction: fr._volume_delta.pressure === "COMPRADORES" ? "BUY" : fr._volume_delta.pressure === "VENDEDORES" ? "SELL" : "NEUTRAL" });
  }
  if (fr._taker_data) {
    results.push({ name: "TAKER_BUY", direction: fr._taker_data.pressure === "COMPRADORES_AGRESSIVOS" ? "BUY" : fr._taker_data.pressure === "VENDEDORES_AGRESSIVOS" ? "SELL" : "NEUTRAL" });
  }
  if (fr._fear_greed) {
    results.push({ name: "FEAR_GREED", direction: fr._fear_greed.value < 25 ? "BUY" : fr._fear_greed.value > 75 ? "SELL" : "NEUTRAL" });
  }
  if (fr._funding_rate !== null && fr._funding_rate !== undefined) {
    results.push({ name: "FUNDING_RATE", direction: fr._funding_rate > 0.0005 ? "SELL" : fr._funding_rate < -0.0005 ? "BUY" : "NEUTRAL" });
  }
  if (ti.divergences) {
    ti.divergences.forEach((d: any) => {
      results.push({ name: `DIV_${d.indicator}`, direction: d.type === "BULLISH" ? "BUY" : "SELL" });
    });
  }
  if (ti.candle_patterns) {
    ti.candle_patterns.forEach((p: any) => {
      results.push({ name: p.name, direction: p.type === "BULLISH" ? "BUY" : "SELL" });
    });
  }
  if (fr._rsi_momentum) {
    results.push({ name: "RSI_SLOPE", direction: fr._rsi_momentum.direction === "ACCELERATING" ? "BUY" : fr._rsi_momentum.direction === "DECELERATING" ? "SELL" : "NEUTRAL" });
  }
  if (fr._ema_crossover?.crossed) {
    results.push({ name: "EMA_CROSSOVER", direction: fr._ema_crossover.type === "GOLDEN_CROSS" ? "BUY" : "SELL" });
  }

  return results;
}

// ============================================================
// UL-AWARE ASYMMETRIC SCORING (v2)
// Score each indicator's contribution using UL values
// ============================================================
function calcULScore(
  direction: string,
  analysisSignal: string,
  status: string,
): { wasCorrect: boolean; ulScore: number } {
  const isBuy = analysisSignal === "COMPRA" || analysisSignal === "BUY";
  const isSell = analysisSignal === "VENDA" || analysisSignal === "SELL";
  const isNeutralSignal = !isBuy && !isSell;
  const isWin = status.startsWith("WIN");
  const isLoss = status === "LOSS";

  if (direction === "NEUTRAL") {
    if (isNeutralSignal) {
      return { wasCorrect: true, ulScore: UL_NEUTRAL_CORRECT };
    }
    if (isLoss) {
      // Neutral indicator warned against a LOSS ÔåÆ excellent
      return { wasCorrect: true, ulScore: UL_LOSS_AVOIDED };
    }
    // Neutral indicator but signal was WIN ÔåÆ missed opportunity (graduated by TP level)
    const missedCost = UL_MISSED_COST[status] || -0.3;
    return { wasCorrect: false, ulScore: missedCost };
  }

  // Directional indicator
  const alignedWithSignal = (direction === "BUY" && isBuy) || (direction === "SELL" && isSell);
  const opposedToSignal = (direction === "BUY" && isSell) || (direction === "SELL" && isBuy);

  if (alignedWithSignal) {
    if (isWin) {
      // Aligned + WIN ÔåÆ graduated reward by TP level
      const reward = UL_VALUES[status] || 1.0;
      return { wasCorrect: true, ulScore: reward };
    }
    // Aligned + LOSS ÔåÆ SEVERE penalty (led to a loss)
    return { wasCorrect: false, ulScore: -3.5 };
  }

  if (opposedToSignal) {
    if (isLoss) {
      // Opposed + LOSS ÔåÆ correctly warned against
      return { wasCorrect: true, ulScore: 2.0 };
    }
    // Opposed + WIN ÔåÆ disagreed but trade worked
    const oppCost = -(UL_VALUES[status] || 1.0) * 0.4;
    return { wasCorrect: false, ulScore: oppCost };
  }

  // Neutral signal context with directional indicator
  if (isNeutralSignal) {
    return { wasCorrect: false, ulScore: 0.0 };
  }

  return { wasCorrect: false, ulScore: 0.0 };
}

// ============================================================
// BACKTEST ENGINE: Sweep thresholds to maximize UL
// ============================================================
interface BacktestResult {
  threshold: number;
  ulTotal: number;
  correct: number;
  total: number;
  changes: number;
  lossesAvoided: number;
  totalLosses: number;
  missedOpps: number;
  totalWins: number;
  lossAvoidanceRate: number;
  missedOpportunityRate: number;
  details: any[];
}

function runBacktest(
  allFinalized: any[],
  weightMap: Map<string, number>,
  threshold: number,
): BacktestResult {
  let ulTotal = 0;
  let correct = 0, total = 0, changes = 0;
  let lossesAvoided = 0, totalLosses = 0;
  let missedOpps = 0, totalWins = 0;
  const details: any[] = [];

  for (const hist of allFinalized) {
    const fr = hist.full_result;
    if (!fr) continue;

    const isWin = hist.status?.startsWith("WIN");
    const isLoss = hist.status === "LOSS";
    const originalSignal = hist.signal || fr?.header?.signal || "NEUTRO";
    const originalNormalized = originalSignal === "COMPRA" || originalSignal === "BUY" ? "COMPRA" :
      originalSignal === "VENDA" || originalSignal === "SELL" ? "VENDA" : "NEUTRO";

    if (isLoss) totalLosses++;
    if (isWin && originalNormalized !== "NEUTRO") totalWins++;

    const indicators = extractIndicatorDirections(fr);
    let buyScore = 0, sellScore = 0, totalWeight = 0;

    for (const ind of indicators) {
      const w = weightMap.get(ind.name) ?? DEFAULT_WEIGHTS[ind.name] ?? 1.0;
      totalWeight += w;
      if (ind.direction === "BUY") buyScore += w;
      else if (ind.direction === "SELL") sellScore += w;
    }

    const buyPct = totalWeight > 0 ? (buyScore / totalWeight) * 100 : 50;
    const sellPct = totalWeight > 0 ? (sellScore / totalWeight) * 100 : 50;

    let recalcSignal = "NEUTRO";
    if (buyPct > threshold) recalcSignal = "COMPRA";
    else if (sellPct > threshold) recalcSignal = "VENDA";

    // Calculate UL contribution for this analysis
    let analysisUL = 0;
    const lossAvoided = isLoss && recalcSignal === "NEUTRO" && originalNormalized !== "NEUTRO";
    const missedOpp = isWin && recalcSignal === "NEUTRO" && originalNormalized !== "NEUTRO";

    if (recalcSignal === "NEUTRO") {
      if (isLoss && originalNormalized !== "NEUTRO") {
        // Loss avoided ÔåÆ positive UL
        analysisUL = UL_LOSS_AVOIDED;
        lossesAvoided++;
      } else if (isWin && originalNormalized !== "NEUTRO") {
        // Missed opportunity ÔåÆ negative UL (graduated)
        analysisUL = UL_MISSED_COST[hist.status] || -0.3;
        missedOpps++;
      } else {
        analysisUL = UL_NEUTRAL_CORRECT;
      }
    } else {
      // Actionable signal
      const recalcAligned = (recalcSignal === "COMPRA" && originalNormalized === "COMPRA") ||
                            (recalcSignal === "VENDA" && originalNormalized === "VENDA");
      if (recalcAligned && isWin) {
        analysisUL = UL_VALUES[hist.status] || 1.0;
      } else if (recalcAligned && isLoss) {
        analysisUL = UL_VALUES.LOSS; // -3.0
      } else if (!recalcAligned && isWin) {
        // Recalc flipped direction on a win ÔåÆ bad
        analysisUL = -(UL_VALUES[hist.status] || 1.0) * 0.5;
      } else if (!recalcAligned && isLoss) {
        // Recalc flipped direction on a loss ÔåÆ might have saved it
        analysisUL = UL_LOSS_AVOIDED * 0.5;
      } else {
        analysisUL = 0;
      }
    }

    ulTotal += analysisUL;
    total++;

    // "Correct" = positive UL contribution
    if (analysisUL > 0) correct++;
    if (recalcSignal !== originalNormalized) changes++;

    details.push({
      id: hist.id,
      original_signal: originalNormalized,
      recalc_signal: recalcSignal,
      actual_result: hist.status,
      buy_pct: parseFloat(buyPct.toFixed(1)),
      sell_pct: parseFloat(sellPct.toFixed(1)),
      ul_contribution: parseFloat(analysisUL.toFixed(2)),
      loss_avoided: lossAvoided,
      missed_opportunity: missedOpp,
    });
  }

  const lossAvoidanceRate = totalLosses > 0 ? (lossesAvoided / totalLosses) * 100 : 0;
  const missedOpportunityRate = totalWins > 0 ? (missedOpps / totalWins) * 100 : 0;

  return {
    threshold, ulTotal: parseFloat(ulTotal.toFixed(2)),
    correct, total, changes,
    lossesAvoided, totalLosses,
    missedOpps, totalWins,
    lossAvoidanceRate, missedOpportunityRate,
    details,
  };
}

// ============================================================
// THRESHOLD SWEEP OPTIMIZER
// Finds the threshold that maximizes UL with safety constraints
// ============================================================
function findOptimalThreshold(
  allFinalized: any[],
  weightMap: Map<string, number>,
): { best: BacktestResult; sweep: Array<{ threshold: number; ul: number; lossAvoid: number; missedOpp: number }> } {
  const MIN_THRESHOLD = 42;
  const MAX_THRESHOLD = 72;
  const STEP = 1;
  const MIN_LOSS_AVOIDANCE = 50; // Safety: must avoid at least 50% of losses

  let bestResult: BacktestResult | null = null;
  let bestUL = -Infinity;
  const sweep: Array<{ threshold: number; ul: number; lossAvoid: number; missedOpp: number }> = [];

  for (let t = MIN_THRESHOLD; t <= MAX_THRESHOLD; t += STEP) {
    const result = runBacktest(allFinalized, weightMap, t);
    sweep.push({
      threshold: t,
      ul: result.ulTotal,
      lossAvoid: parseFloat(result.lossAvoidanceRate.toFixed(1)),
      missedOpp: parseFloat(result.missedOpportunityRate.toFixed(1)),
    });

    // Safety constraint: lossAvoidanceRate must be >= 50%
    // (unless there are very few losses where any threshold would fail)
    const passesConstraint = result.totalLosses < 3 || result.lossAvoidanceRate >= MIN_LOSS_AVOIDANCE;

    if (passesConstraint && result.ulTotal > bestUL) {
      bestUL = result.ulTotal;
      bestResult = result;
    }
  }

  // Fallback: if no threshold passes constraint, use the one with highest UL anyway
  if (!bestResult) {
    for (let t = MIN_THRESHOLD; t <= MAX_THRESHOLD; t += STEP) {
      const result = runBacktest(allFinalized, weightMap, t);
      if (result.ulTotal > bestUL) {
        bestUL = result.ulTotal;
        bestResult = result;
      }
    }
  }

  // Anti-stagnation guard
  if (bestResult) {
    if (bestResult.missedOpportunityRate > 60 && bestResult.threshold > MIN_THRESHOLD + 3) {
      // Too conservative: force threshold down
      const adjusted = runBacktest(allFinalized, weightMap, bestResult.threshold - 3);
      console.log(`[AUTO-REFINE] Anti-stagnation: missedOpp ${bestResult.missedOpportunityRate.toFixed(1)}% > 60%, lowering threshold ${bestResult.threshold} ÔåÆ ${adjusted.threshold}`);
      bestResult = adjusted;
    }
    if (bestResult.lossAvoidanceRate < 30 && bestResult.threshold < MAX_THRESHOLD - 3) {
      // Too aggressive: force threshold up
      const adjusted = runBacktest(allFinalized, weightMap, bestResult.threshold + 3);
      console.log(`[AUTO-REFINE] Anti-stagnation: lossAvoid ${bestResult.lossAvoidanceRate.toFixed(1)}% < 30%, raising threshold ${bestResult.threshold} ÔåÆ ${adjusted.threshold}`);
      bestResult = adjusted;
    }
  }

  return { best: bestResult!, sweep };
}

// ============================================================
// MAIN HANDLER
// ============================================================
serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const supabase = createClient(supabaseUrl, serviceRoleKey);

    const body = await req.json().catch(() => ({}));
    const mode = body.mode || "full"; // "extract" | "calibrate" | "full" | "reset"

    console.log(`[AUTO-REFINE] Starting mode: ${mode} | UL-Maximizer v2 | Regra P├®trea: Max UL (evitar LOSS > capturar WIN)`);

    const results: any = { extracted: 0, calibrated: 0, logs: [] };

    // ========== STEP 1: EXTRACT INDICATOR PERFORMANCE ==========
    if (mode === "extract" || mode === "full") {
      const { data: finalizedAnalyses, error: fetchErr } = await supabase
        .from("auto_management_history")
        .select("id, asset, timeframe, signal, status, full_result, created_at")
        .in("status", ["WIN_TP1", "WIN_TP2", "WIN_TP3", "WIN", "LOSS"])
        .is("deleted_at", null)
        .order("created_at", { ascending: false })
        .limit(500);

      if (fetchErr) throw new Error(`Fetch error: ${fetchErr.message}`);

      const analysisIds = (finalizedAnalyses || []).map((a: any) => a.id);
      const { data: existingPerf } = await supabase
        .from("management_indicator_performance")
        .select("analysis_id")
        .in("analysis_id", analysisIds.length > 0 ? analysisIds : ["__none__"]);

      const existingSet = new Set((existingPerf || []).map((p: any) => p.analysis_id));
      const newAnalyses = (finalizedAnalyses || []).filter((a: any) => !existingSet.has(a.id));

      console.log(`[AUTO-REFINE] Found ${finalizedAnalyses?.length || 0} finalized, ${newAnalyses.length} new to extract`);

      for (const analysis of newAnalyses) {
        const fullResult = analysis.full_result;
        if (!fullResult) continue;

        const analysisSignal = analysis.signal || fullResult?.header?.signal || "NEUTRO";
        const indicators = extractIndicatorDirections(fullResult);
        const indicatorRecords: any[] = [];

        for (const ind of indicators) {
          const { wasCorrect } = calcULScore(ind.direction, analysisSignal, analysis.status);

          indicatorRecords.push({
            analysis_id: analysis.id,
            asset: analysis.asset,
            timeframe: analysis.timeframe,
            indicator_name: ind.name,
            direction_suggested: ind.direction,
            weight_used: DEFAULT_WEIGHTS[ind.name] || 1.0,
            actual_result: analysis.status.startsWith("WIN") ? "WIN" : "LOSS",
            was_correct: wasCorrect,
          });
        }

        if (indicatorRecords.length > 0) {
          const { error: insertErr } = await supabase
            .from("management_indicator_performance")
            .insert(indicatorRecords);
          if (insertErr) {
            console.error(`[AUTO-REFINE] Insert error for ${analysis.id}:`, insertErr.message);
          } else {
            results.extracted += indicatorRecords.length;
          }
        }
      }

      console.log(`[AUTO-REFINE] Extracted ${results.extracted} indicator records from ${newAnalyses.length} analyses`);
    }

    // ========== STEP 2: UL-GRADIENT CALIBRATION ==========
    if (mode === "calibrate" || mode === "full") {
      const { data: combos } = await supabase
        .from("management_indicator_performance")
        .select("asset, timeframe")
        .limit(1000);

      const uniqueCombos = new Map<string, { asset: string; timeframe: string }>();
      (combos || []).forEach((c: any) => {
        const key = `${c.asset}_${c.timeframe}`;
        if (!uniqueCombos.has(key)) uniqueCombos.set(key, { asset: c.asset, timeframe: c.timeframe });
      });

      for (const [_, combo] of uniqueCombos) {
        const { asset, timeframe } = combo;

        // Get all finalized analyses for backtest
        const { data: allFinalized } = await supabase
          .from("auto_management_history")
          .select("id, asset, timeframe, signal, status, full_result, created_at")
          .eq("asset", asset)
          .eq("timeframe", timeframe)
          .in("status", ["WIN_TP1", "WIN_TP2", "WIN_TP3", "WIN", "LOSS"])
          .is("deleted_at", null)
          .limit(500);

        // Get indicator performance with analysis status for UL scoring
        const { data: perfData } = await supabase
          .from("management_indicator_performance")
          .select("indicator_name, was_correct, weight_used, actual_result, direction_suggested, created_at, analysis_id")
          .eq("asset", asset)
          .eq("timeframe", timeframe);

        if (!perfData || perfData.length < 5) {
          console.log(`[AUTO-REFINE] Skipping ${asset}/${timeframe}: only ${perfData?.length || 0} records (need 5+)`);
          continue;
        }

        // Build analysis status lookup for UL scoring
        const analysisStatusMap = new Map<string, string>();
        (allFinalized || []).forEach((a: any) => analysisStatusMap.set(a.id, a.status));

        // Build analysis signal lookup
        const analysisSignalMap = new Map<string, string>();
        (allFinalized || []).forEach((a: any) => {
          const sig = a.signal || a.full_result?.header?.signal || "NEUTRO";
          analysisSignalMap.set(a.id, sig);
        });

        // ============================================================
        // UL-GRADIENT CALIBRATION per indicator
        // ============================================================
        const indicatorStats = new Map<string, {
          ulContribTotal: number;
          weightedTotal: number;
          rawCorrect: number;
          rawTotal: number;
          losses: number;
          wins: number;
          originalWeight: number;
        }>();

        perfData.forEach((p: any) => {
          const tempWeight = getTemporalWeight(p.created_at);
          const status = analysisStatusMap.get(p.analysis_id) || (p.actual_result === "WIN" ? "WIN_TP1" : "LOSS");
          const signal = analysisSignalMap.get(p.analysis_id) || "NEUTRO";

          const { wasCorrect, ulScore } = calcULScore(p.direction_suggested, signal, status);

          const existing = indicatorStats.get(p.indicator_name) || {
            ulContribTotal: 0, weightedTotal: 0,
            rawCorrect: 0, rawTotal: 0,
            losses: 0, wins: 0,
            originalWeight: p.weight_used || 1,
          };

          existing.ulContribTotal += ulScore * tempWeight;
          existing.weightedTotal += tempWeight;
          existing.rawTotal++;
          if (wasCorrect) existing.rawCorrect++;
          if (p.actual_result === "LOSS") existing.losses++;
          if (p.actual_result === "WIN") existing.wins++;

          indicatorStats.set(p.indicator_name, existing);
        });

        // Overall WR before
        const totalCorrect = perfData.filter((p: any) => p.was_correct).length;
        const overallWRBefore = (totalCorrect / perfData.length) * 100;

        const adjustments: any[] = [];
        const upsertRows: any[] = [];

        for (const [indicatorName, stats] of indicatorStats) {
          const rawWr = stats.rawTotal > 0 ? (stats.rawCorrect / stats.rawTotal) * 100 : 50;
          const originalWeight = DEFAULT_WEIGHTS[indicatorName] || stats.originalWeight || 1.0;

          // UL Contribution per participation (normalized)
          const ulContrib = stats.weightedTotal > 0 ? stats.ulContribTotal / stats.weightedTotal : 0;

          let calibratedWeight = originalWeight;
          let trend = "STABLE";

          // Minimum 5 samples to calibrate
          if (stats.rawTotal >= 5) {
            // KILL SWITCH: if UL_contrib < -2.0 with 5+ loss participations ÔåÆ silence
            if (ulContrib < -2.0 && stats.losses >= 5) {
              calibratedWeight = 0.05;
              trend = "KILLED";
              adjustments.push({
                indicator: indicatorName, action: "KILL",
                wr: rawWr.toFixed(1), ul_contrib: ulContrib.toFixed(3),
                losses: stats.losses,
                from: originalWeight, to: 0.05,
                samples: stats.rawTotal,
              });
            } else if (ulContrib > 0.5) {
              // Strong positive UL ÔåÆ boost (up to 1.4x original, cap at 4.0)
              const boostFactor = 1.0 + Math.min(0.4, (ulContrib - 0.5) * 0.3);
              calibratedWeight = Math.min(originalWeight * boostFactor, Math.min(originalWeight * 2.0, 4.0));
              trend = "IMPROVING";
              adjustments.push({
                indicator: indicatorName, action: "BOOST",
                wr: rawWr.toFixed(1), ul_contrib: ulContrib.toFixed(3),
                from: originalWeight, to: parseFloat(calibratedWeight.toFixed(2)),
                samples: stats.rawTotal,
              });
            } else if (ulContrib < -0.3) {
              // Negative UL ÔåÆ reduce proportionally (floor at 0.1)
              const reduceFactor = Math.max(0.15, 1.0 + (ulContrib * 0.5));
              calibratedWeight = Math.max(originalWeight * reduceFactor, 0.1);
              trend = "DEGRADING";
              adjustments.push({
                indicator: indicatorName, action: "REDUCE",
                wr: rawWr.toFixed(1), ul_contrib: ulContrib.toFixed(3),
                from: originalWeight, to: parseFloat(calibratedWeight.toFixed(2)),
                samples: stats.rawTotal,
              });
            }
            // Between -0.3 and 0.5: stable
          }

          upsertRows.push({
            asset,
            timeframe,
            indicator_name: indicatorName,
            original_weight: originalWeight,
            calibrated_weight: parseFloat(calibratedWeight.toFixed(4)),
            win_rate: parseFloat(rawWr.toFixed(2)),
            sample_count: stats.rawTotal,
            trend,
            last_calibrated_at: new Date().toISOString(),
          });
        }

        // Upsert refinement weights
        if (upsertRows.length > 0) {
          const { error: upsertErr } = await supabase
            .from("management_refinement_weights")
            .upsert(upsertRows, { onConflict: "asset,timeframe,indicator_name" });
          if (upsertErr) {
            console.error(`[AUTO-REFINE] Upsert error for ${asset}/${timeframe}:`, upsertErr.message);
          } else {
            results.calibrated += upsertRows.length;
          }
        }

        // ========== THRESHOLD SWEEP OPTIMIZER ==========
        const newWeightMap = new Map<string, number>();
        upsertRows.forEach((r: any) => newWeightMap.set(r.indicator_name, r.calibrated_weight));

        const allFinalizedArr = allFinalized || [];
        if (allFinalizedArr.length >= 3) {
          const { best, sweep } = findOptimalThreshold(allFinalizedArr, newWeightMap);

          const projectedWR = best.total > 0 ? (best.correct / best.total) * 100 : null;

          // Log calibration run
          const { error: logErr } = await supabase
            .from("management_refinement_log")
            .insert({
              asset,
              timeframe,
              overall_wr_before: parseFloat(overallWRBefore.toFixed(2)),
              overall_wr_after: projectedWR !== null ? parseFloat(projectedWR.toFixed(2)) : parseFloat(overallWRBefore.toFixed(2)),
              indicators_adjusted: adjustments.length,
              adjustments_json: adjustments,
              analysis_count: perfData.length,
              projected_wr_new_weights: projectedWR !== null ? parseFloat(projectedWR.toFixed(2)) : null,
              backtest_signal_changes: best.changes,
              backtest_details: best.details.length > 0 ? best.details : null,
              loss_avoidance_rate: parseFloat(best.lossAvoidanceRate.toFixed(2)),
              missed_opportunity_rate: parseFloat(best.missedOpportunityRate.toFixed(2)),
              effective_threshold: best.threshold,
            });

          if (logErr) console.error(`[AUTO-REFINE] Log error:`, logErr.message);

          results.logs.push({
            asset, timeframe,
            totalIndicators: upsertRows.length,
            adjusted: adjustments.length,
            overallWR: overallWRBefore.toFixed(1),
            projectedWR: projectedWR?.toFixed(1) || "N/A",
            ulTotal: best.ulTotal,
            optimalThreshold: best.threshold,
            signalChanges: best.changes,
            lossAvoidanceRate: best.lossAvoidanceRate.toFixed(1),
            missedOpportunityRate: best.missedOpportunityRate.toFixed(1),
            backtestSamples: best.total,
            samples: perfData.length,
            thresholdSweep: sweep,
          });

          console.log(`[AUTO-REFINE] Ô£à ${asset}/${timeframe}: UL=${best.ulTotal} | WR ${overallWRBefore.toFixed(1)}% ÔåÆ ${projectedWR?.toFixed(1) || "N/A"}% | Threshold: ${best.threshold}% | LossAvoid: ${best.lossAvoidanceRate.toFixed(1)}% | MissedOpp: ${best.missedOpportunityRate.toFixed(1)}% | ${best.changes} changes`);
        } else {
          console.log(`[AUTO-REFINE] Skipping backtest for ${asset}/${timeframe}: only ${allFinalizedArr.length} finalized (need 3+)`);
        }
      }
    }

    // ========== RESET MODE ==========
    if (mode === "reset") {
      await supabase.from("management_refinement_weights").delete().neq("id", "00000000-0000-0000-0000-000000000000");
      await supabase.from("management_indicator_performance").delete().neq("id", "00000000-0000-0000-0000-000000000000");
      results.logs.push({ action: "RESET", message: "All refinement data cleared" });
      console.log(`[AUTO-REFINE] Reset complete`);
    }

    console.log(`[AUTO-REFINE] Done. Extracted: ${results.extracted}, Calibrated: ${results.calibrated}`);

    return new Response(JSON.stringify({ success: true, ...results }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (err) {
    console.error("[AUTO-REFINE] Fatal error:", err);
    return new Response(JSON.stringify({ error: String(err) }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type",
};

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const supabase = createClient(supabaseUrl, serviceRoleKey);

    console.log("[reprocess-history] Starting full reprocessing...");

    // Step 1: Mark ALL existing non-deleted analyses as _legacy_bias
    const { data: existing, error: fetchErr } = await supabase
      .from("auto_analysis_history")
      .select("id, full_result")
      .is("deleted_at", null);

    if (fetchErr) {
      console.error("[reprocess-history] Failed to fetch existing:", fetchErr.message);
    } else if (existing && existing.length > 0) {
      let marked = 0;
      for (const entry of existing) {
        const fullResult = (entry.full_result || {}) as Record<string, any>;
        if (!fullResult._legacy_bias) {
          fullResult._legacy_bias = true;
          fullResult._legacy_bias_marked_at = new Date().toISOString();
          const { error: updateErr } = await supabase
            .from("auto_analysis_history")
            .update({ full_result: fullResult })
            .eq("id", entry.id);
          if (!updateErr) marked++;
        }
      }
      console.log(`[reprocess-history] Marked ${marked}/${existing.length} entries as _legacy_bias`);
    }

    // Step 2: Run new analyses for all active configs
    const { data: configs, error: cfgErr } = await supabase
      .from("auto_analysis_configs")
      .select("*")
      .eq("is_active", true);

    if (cfgErr) {
      console.error("[reprocess-history] Failed to fetch configs:", cfgErr.message);
      return new Response(JSON.stringify({ error: cfgErr.message }), {
        status: 500,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    let newAnalyses = 0;

    if (configs && configs.length > 0) {
      for (const config of configs) {
        try {
          if (newAnalyses > 0) {
            console.log(`[reprocess-history] Waiting 5s before next analysis...`);
            await new Promise(r => setTimeout(r, 5000));
          }

          console.log(`[reprocess-history] Analyzing ${config.asset} ${config.timeframe}...`);

          const analyzeUrl = `${supabaseUrl}/functions/v1/analyze-asset`;
          let analyzeResponse: Response | null = null;

          for (let attempt = 0; attempt <= 2; attempt++) {
            analyzeResponse = await fetch(analyzeUrl, {
              method: "POST",
              headers: {
                "Content-Type": "application/json",
                Authorization: `Bearer ${serviceRoleKey}`,
              },
              body: JSON.stringify({
                asset: config.asset,
                timeframe: config.timeframe,
              }),
            });

            if (analyzeResponse.ok) break;
            if (analyzeResponse.status === 503 && attempt < 2) {
              await new Promise(r => setTimeout(r, (attempt + 1) * 5000));
              continue;
            }
          }

          if (!analyzeResponse || !analyzeResponse.ok) {
            const errText = analyzeResponse ? await analyzeResponse.text() : "No response";
            console.error(`[reprocess-history] Analysis failed for ${config.asset}: ${errText}`);
            continue;
          }

          const result = await analyzeResponse.json();
          const header = result.header || {};
          const rm = result.risk_management || {};
          const rawSignal = String(header.signal || "NEUTRO").trim().toUpperCase();
          const signal = rawSignal === "BUY" || rawSignal === "LONG"
            ? "COMPRA"
            : rawSignal === "SELL" || rawSignal === "SHORT"
              ? "VENDA"
              : rawSignal;
          const isNeutral = signal === "NEUTRO" || signal === "NEUTRAL";

          const { error: insertErr } = await supabase
            .from("auto_analysis_history")
            .insert({
              config_id: config.id,
              asset: config.asset,
              timeframe: config.timeframe,
              signal,
              signal_strength_pct: header.signal_strength_pct || null,
              final_confidence_pct: header.final_confidence_pct || null,
              entry_price: isNeutral ? null : (rm.entry_price || null),
              stop_loss: isNeutral ? null : (rm.stop_loss || null),
              take_profit_1: isNeutral ? null : (rm.take_profit_1 || null),
              take_profit_2: isNeutral ? null : (rm.take_profit_2 || null),
              take_profit_3: isNeutral ? null : (rm.take_profit_3 || null),
              trend: header.trend || null,
              risk_reward_ratio: isNeutral ? null : (rm.risk_reward_ratio || null),
              executive_summary: result.institutional_synthesis?.executive_summary || null,
              full_result: result,
              status: isNeutral ? "NEUTRAL" : "PENDING",
            });

          if (insertErr) {
            console.error(`[reprocess-history] Insert failed for ${config.asset}:`, insertErr.message);
            continue;
          }

          // Update last_run_at
          await supabase
            .from("auto_analysis_configs")
            .update({ last_run_at: new Date().toISOString() })
            .eq("id", config.id);

          newAnalyses++;
          console.log(`[reprocess-history] Ô£à ${config.asset} ${config.timeframe} ÔÇö Signal: ${signal}, Confidence: ${header.final_confidence_pct}%`);
        } catch (err) {
          console.error(`[reprocess-history] Error processing ${config.asset}:`, err);
        }
      }
    }

    // Step 3: Re-verify all PENDING analyses
    console.log("[reprocess-history] Triggering verification of all PENDING analyses...");
    try {
      const verifyUrl = `${supabaseUrl}/functions/v1/verify-analyses-results`;
      const verifyRes = await fetch(verifyUrl, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${serviceRoleKey}`,
        },
        body: JSON.stringify({}),
      });
      if (verifyRes.ok) {
        const verifyResult = await verifyRes.json();
        console.log(`[reprocess-history] Verification complete:`, JSON.stringify(verifyResult));
      } else {
        console.error(`[reprocess-history] Verification failed: ${await verifyRes.text()}`);
      }
    } catch (err) {
      console.error("[reprocess-history] Verification error:", err);
    }

    const summary = {
      success: true,
      legacy_entries_marked: existing?.length || 0,
      new_analyses: newAnalyses,
      total_configs: configs?.length || 0,
    };

    console.log(`[reprocess-history] Done.`, JSON.stringify(summary));

    return new Response(JSON.stringify(summary), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (err) {
    console.error("[reprocess-history] Fatal error:", err);
    return new Response(JSON.stringify({ error: String(err) }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type, x-supabase-client-platform, x-supabase-client-platform-version, x-supabase-client-runtime, x-supabase-client-runtime-version",
};

// ============================================================
// CONSTANTS
// ============================================================

const FEE_TAKER = 0.0005; // 0.05% Binance Futures Taker
const FEE_MAKER = 0.0002; // 0.02% Binance Futures Maker
const SLIPPAGE_BUFFER = 0.0002; // 0.02% safety margin for STOP_MARKET slippage
const PARTIAL_PCT = 0.3333; // 33.33% per TP level

// ============================================================
// TRUE BREAKEVEN CALCULATION
// ============================================================

function calcTrueBreakeven(
  avgPrice: number,
  side: "LONG" | "SHORT",
  totalFees?: number
): number {
  // Default: Taker open + Taker close + slippage buffer = 0.12% total
  const feeRate = totalFees ?? (FEE_TAKER + FEE_TAKER + SLIPPAGE_BUFFER);
  if (side === "LONG") {
    return avgPrice * (1 + feeRate);
  } else {
    return avgPrice * (1 - feeRate);
  }
}

// ============================================================
// DCA: WEIGHTED AVERAGE PRICE
// ============================================================

function calcWeightedAvgPrice(
  currentQty: number,
  currentAvgPrice: number,
  newQty: number,
  newPrice: number
): { totalQty: number; avgPrice: number } {
  const totalQty = currentQty + newQty;
  const avgPrice =
    (currentQty * currentAvgPrice + newQty * newPrice) / totalQty;
  return { totalQty, avgPrice };
}

// ============================================================
// BINANCE PROXY HELPER
// ============================================================

async function callBinanceProxy(
  supabaseUrl: string,
  authHeader: string,
  apikey: string,
  body: Record<string, unknown>
): Promise<any> {
  const res = await fetch(`${supabaseUrl}/functions/v1/binance-proxy`, {
    method: "POST",
    headers: {
      Authorization: authHeader,
      apikey,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(body),
  });
  return res.json();
}

// ============================================================
// MAIN HANDLER
// ============================================================

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const authHeader = req.headers.get("authorization");
    if (!authHeader) {
      return new Response(JSON.stringify({ error: "Not authenticated" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const supabaseKey = Deno.env.get("SUPABASE_ANON_KEY")!;
    const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;

    const supabase = createClient(supabaseUrl, supabaseKey, {
      global: { headers: { Authorization: authHeader } },
    });

    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser();
    if (authError || !user) {
      return new Response(JSON.stringify({ error: "Invalid token" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const body = await req.json();
    const { action } = body;

    // ========================================================
    // ACTION: create_position
    // Called after autotrade-engine places the entry order
    // ========================================================
    if (action === "create_position") {
      const {
        symbol, side, size, entry_price, stop_loss, take_profit_1,
        take_profit_2, take_profit_3, leverage, risk_pct,
        entry_order_id, sl_order_id, analysis_id, tp_type,
      } = body;

      const trueBreakeven = calcTrueBreakeven(entry_price, side);
      const partialSize = parseFloat((size * PARTIAL_PCT).toFixed(8));

      const { data: pos, error: insertErr } = await supabase
        .from("trade_positions")
        .insert({
          user_id: user.id,
          analysis_id: analysis_id || null,
          symbol,
          side,
          trade_state: "ACTIVE",
          original_size: size,
          total_position_size: size,
          current_avg_price: entry_price,
          true_breakeven_price: trueBreakeven,
          accumulated_fees: size * entry_price * FEE_TAKER, // open fee
          partial_size: partialSize,
          entry_price,
          stop_loss_original: stop_loss,
          stop_loss_current: stop_loss,
          take_profit_1,
          take_profit_2: take_profit_2 || null,
          take_profit_3: take_profit_3 || null,
          tp_type: tp_type || "FIXED_PRICE",
          leverage: leverage || 1,
          risk_pct: risk_pct || 2,
          entry_order_id: entry_order_id || null,
          sl_order_id: sl_order_id || null,
          dca_history: [{ price: entry_price, qty: size, time: new Date().toISOString() }],
        })
        .select()
        .single();

      if (insertErr) {
        return new Response(JSON.stringify({ error: insertErr.message }), {
          status: 500,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }

      console.log(`[trade-manager] Created position ${pos.id}: ${side} ${size} ${symbol} @ ${entry_price}`);
      return new Response(JSON.stringify({ success: true, position: pos }), {
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    // ========================================================
    // ACTION: check_and_advance
    // Monitors price and advances state machine
    // ========================================================
    if (action === "check_and_advance") {
      const { position_id, current_price } = body;

      const { data: pos, error: fetchErr } = await supabase
        .from("trade_positions")
        .select("*")
        .eq("id", position_id)
        .eq("user_id", user.id)
        .single();

      if (fetchErr || !pos) {
        return new Response(JSON.stringify({ error: "Position not found" }), {
          status: 404,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }

      if (pos.trade_state === "CLOSED") {
        return new Response(JSON.stringify({ message: "Position already closed" }), {
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }

      const isLong = pos.side === "LONG";
      const price = current_price;
      const now = new Date().toISOString();
      const updates: Record<string, any> = { unrealized_pnl: 0 };
      const actions: string[] = [];

      // Calculate unrealized P&L
      if (isLong) {
        updates.unrealized_pnl = ((price - pos.current_avg_price) / pos.current_avg_price) * 100;
      } else {
        updates.unrealized_pnl = ((pos.current_avg_price - price) / pos.current_avg_price) * 100;
      }

      // ---- CHECK STOP LOSS HIT ----
      const slHit = isLong ? price <= pos.stop_loss_current : price >= pos.stop_loss_current;

      if (slHit) {
        // Determine final state based on current trade_state
        let finalState = "CLOSED";
        let closeReason = "LOSS";

        if (pos.trade_state === "TP2_HIT") {
          closeReason = "WIN_TP2_THEN_SL";
        } else if (pos.trade_state === "TP1_HIT") {
          closeReason = "WIN_TP1_THEN_SL";
        }

        updates.trade_state = finalState;
        updates.sl_filled_at = now;
        updates.closed_at = now;
        updates.close_reason = closeReason;
        actions.push(`SL hit at ${price}. State: ${pos.trade_state} ÔåÆ CLOSED (${closeReason})`);

        // Close remaining position via Binance
        const closeSide = isLong ? "SELL" : "BUY";
        const remaining = pos.total_position_size;
        if (remaining > 0) {
          await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
            action: "place_order",
            symbol: pos.symbol,
            side: closeSide,
            type: "MARKET",
            quantity: remaining,
            reduceOnly: true,
          });
          actions.push(`Closed ${remaining} ${pos.symbol} at market (Reduce-Only)`);
        }

        // Cancel pending SL/TP orders
        await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
          action: "cancel_all",
          symbol: pos.symbol,
        });
        actions.push("Cancelled all pending orders");

      } else {
        // ---- STATE MACHINE: TP ADVANCEMENT ----

        // PHASE 1: ACTIVE ÔåÆ TP1_HIT
        if (pos.trade_state === "ACTIVE") {
          const tp1Hit = isLong ? price >= pos.take_profit_1 : price <= pos.take_profit_1;
          if (tp1Hit) {
            const closeSide = isLong ? "SELL" : "BUY";

            // Action 1: Close 33.33% at market (Reduce-Only)
            const partialQty = parseFloat(pos.partial_size.toFixed(8));
            const closeResult = await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
              action: "place_order",
              symbol: pos.symbol,
              side: closeSide,
              type: "MARKET",
              quantity: partialQty,
              reduceOnly: true,
            });
            actions.push(`TP1: Closed ${partialQty} ${pos.symbol} (Reduce-Only)`);

            // Action 2: Cancel old SL, place new SL at True Breakeven
            await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
              action: "cancel_all",
              symbol: pos.symbol,
            });

            const remainingQty = parseFloat((pos.total_position_size - partialQty).toFixed(8));
            const slResult = await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
              action: "place_order",
              symbol: pos.symbol,
              side: closeSide,
              type: "STOP_MARKET",
              quantity: remainingQty,
              stopPrice: pos.true_breakeven_price,
              reduceOnly: true,
            });
            actions.push(`New SL at True Breakeven: ${pos.true_breakeven_price}`);

            // Calculate partial realized PnL
            const partialPnl = isLong
              ? (price - pos.current_avg_price) * partialQty
              : (pos.current_avg_price - price) * partialQty;

            updates.trade_state = "TP1_HIT";
            updates.tp1_filled_at = now;
            updates.total_position_size = remainingQty;
            updates.stop_loss_current = pos.true_breakeven_price;
            updates.realized_pnl = (pos.realized_pnl || 0) + partialPnl;
            updates.sl_order_id = slResult?.orderId || null;
            // Recalculate partial_size for remaining
            updates.partial_size = parseFloat((remainingQty * 0.5).toFixed(8)); // 50% of remaining = ~33% of original
          }
        }

        // PHASE 2: TP1_HIT ÔåÆ TP2_HIT
        else if (pos.trade_state === "TP1_HIT" && pos.take_profit_2) {
          const tp2Hit = isLong ? price >= pos.take_profit_2 : price <= pos.take_profit_2;
          if (tp2Hit) {
            const closeSide = isLong ? "SELL" : "BUY";
            const partialQty = parseFloat(pos.partial_size.toFixed(8));

            // Action 1: Close partial at market
            await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
              action: "place_order",
              symbol: pos.symbol,
              side: closeSide,
              type: "MARKET",
              quantity: partialQty,
              reduceOnly: true,
            });
            actions.push(`TP2: Closed ${partialQty} ${pos.symbol} (Reduce-Only)`);

            // Action 2: Cancel old SL, place new SL at TP1 price (trailing stop staircase)
            await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
              action: "cancel_all",
              symbol: pos.symbol,
            });

            const remainingQty = parseFloat((pos.total_position_size - partialQty).toFixed(8));
            const slResult = await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
              action: "place_order",
              symbol: pos.symbol,
              side: closeSide,
              type: "STOP_MARKET",
              quantity: remainingQty,
              stopPrice: pos.take_profit_1, // Trailing: SL moves to TP1
              reduceOnly: true,
            });
            actions.push(`New SL at TP1 price: ${pos.take_profit_1} (trailing staircase)`);

            const partialPnl = isLong
              ? (price - pos.current_avg_price) * partialQty
              : (pos.current_avg_price - price) * partialQty;

            updates.trade_state = "TP2_HIT";
            updates.tp2_filled_at = now;
            updates.total_position_size = remainingQty;
            updates.stop_loss_current = pos.take_profit_1;
            updates.realized_pnl = (pos.realized_pnl || 0) + partialPnl;
            updates.sl_order_id = slResult?.orderId || null;
            updates.partial_size = remainingQty; // TP3 closes 100% remaining
          }
        }

        // PHASE 3: TP2_HIT ÔåÆ CLOSED (TP3 = close all)
        else if (pos.trade_state === "TP2_HIT" && pos.take_profit_3) {
          const tp3Hit = isLong ? price >= pos.take_profit_3 : price <= pos.take_profit_3;
          if (tp3Hit) {
            const closeSide = isLong ? "SELL" : "BUY";
            const remainingQty = pos.total_position_size;

            // Close 100% remaining at market
            await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
              action: "place_order",
              symbol: pos.symbol,
              side: closeSide,
              type: "MARKET",
              quantity: remainingQty,
              reduceOnly: true,
            });
            actions.push(`TP3: Closed ALL ${remainingQty} ${pos.symbol} (Reduce-Only)`);

            // Cancel all pending
            await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
              action: "cancel_all",
              symbol: pos.symbol,
            });

            const partialPnl = isLong
              ? (price - pos.current_avg_price) * remainingQty
              : (pos.current_avg_price - price) * remainingQty;

            updates.trade_state = "CLOSED";
            updates.tp3_filled_at = now;
            updates.closed_at = now;
            updates.close_reason = "WIN_TP3";
            updates.total_position_size = 0;
            updates.realized_pnl = (pos.realized_pnl || 0) + partialPnl;
          }
        }
      }

      // Apply updates
      if (Object.keys(updates).length > 0) {
        const { error: updateErr } = await supabase
          .from("trade_positions")
          .update(updates)
          .eq("id", position_id);

        if (updateErr) {
          console.error(`[trade-manager] Update failed:`, updateErr.message);
        }
      }

      console.log(`[trade-manager] ${pos.symbol} ${position_id}: ${actions.join(" | ") || "No state change"}`);
      return new Response(
        JSON.stringify({
          success: true,
          position_id,
          trade_state: updates.trade_state || pos.trade_state,
          actions,
        }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // ========================================================
    // ACTION: dca_entry (Scaling In / DCA)
    // ========================================================
    if (action === "dca_entry") {
      const { position_id, new_price, new_qty } = body;

      const { data: pos, error: fetchErr } = await supabase
        .from("trade_positions")
        .select("*")
        .eq("id", position_id)
        .eq("user_id", user.id)
        .single();

      if (fetchErr || !pos) {
        return new Response(JSON.stringify({ error: "Position not found" }), {
          status: 404,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }

      if (pos.trade_state === "CLOSED") {
        return new Response(JSON.stringify({ error: "Cannot DCA into closed position" }), {
          status: 400,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }

      // 1. Recalculate weighted average
      const { totalQty, avgPrice } = calcWeightedAvgPrice(
        pos.total_position_size,
        pos.current_avg_price,
        new_qty,
        new_price
      );

      // 2. Accumulate fees
      const newFee = new_qty * new_price * FEE_TAKER;
      const totalFees = pos.accumulated_fees + newFee;
      const feeRate = totalFees / (totalQty * avgPrice);

      // 3. Recalculate true breakeven with accumulated fees
      const trueBreakeven = calcTrueBreakeven(avgPrice, pos.side as "LONG" | "SHORT", feeRate + FEE_TAKER);

      // 4. New partial size
      const newPartialSize = parseFloat((totalQty * PARTIAL_PCT).toFixed(8));

      // 5. DCA history
      const dcaHistory = [...(pos.dca_history || []), { price: new_price, qty: new_qty, time: new Date().toISOString() }];

      // 6. Cancel and replace SL on Binance
      const closeSide = pos.side === "LONG" ? "SELL" : "BUY";
      await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
        action: "cancel_all",
        symbol: pos.symbol,
      });

      // Place new SL with updated size at original invalidation price
      const slResult = await callBinanceProxy(supabaseUrl, authHeader, supabaseKey, {
        action: "place_order",
        symbol: pos.symbol,
        side: closeSide,
        type: "STOP_MARKET",
        quantity: totalQty,
        stopPrice: pos.stop_loss_original, // Keep original invalidation
        reduceOnly: true,
      });

      // 7. Recalculate TPs if PERCENTAGE type
      const updates: Record<string, any> = {
        total_position_size: totalQty,
        current_avg_price: avgPrice,
        true_breakeven_price: trueBreakeven,
        accumulated_fees: totalFees,
        partial_size: newPartialSize,
        dca_count: pos.dca_count + 1,
        dca_history: dcaHistory,
        sl_order_id: slResult?.orderId || null,
      };

      if (pos.tp_type === "PERCENTAGE") {
        // Recalculate TP levels from new average price
        const tp1Pct = (pos.take_profit_1 - pos.entry_price) / pos.entry_price;
        const isLong = pos.side === "LONG";
        updates.take_profit_1 = isLong ? avgPrice * (1 + tp1Pct) : avgPrice * (1 - tp1Pct);
        if (pos.take_profit_2) {
          const tp2Pct = (pos.take_profit_2 - pos.entry_price) / pos.entry_price;
          updates.take_profit_2 = isLong ? avgPrice * (1 + Math.abs(tp2Pct)) : avgPrice * (1 - Math.abs(tp2Pct));
        }
        if (pos.take_profit_3) {
          const tp3Pct = (pos.take_profit_3 - pos.entry_price) / pos.entry_price;
          updates.take_profit_3 = isLong ? avgPrice * (1 + Math.abs(tp3Pct)) : avgPrice * (1 - Math.abs(tp3Pct));
        }
      }

      const { error: updateErr } = await supabase
        .from("trade_positions")
        .update(updates)
        .eq("id", position_id);

      if (updateErr) {
        return new Response(JSON.stringify({ error: updateErr.message }), {
          status: 500,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }

      console.log(`[trade-manager] DCA #${pos.dca_count + 1}: ${pos.symbol} +${new_qty} @ ${new_price} ÔåÆ Avg: ${avgPrice.toFixed(4)}, BE: ${trueBreakeven.toFixed(4)}`);
      return new Response(
        JSON.stringify({
          success: true,
          new_avg_price: avgPrice,
          true_breakeven: trueBreakeven,
          total_size: totalQty,
          partial_size: newPartialSize,
          dca_count: pos.dca_count + 1,
        }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    return new Response(
      JSON.stringify({ error: `Unknown action: ${action}` }),
      { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    console.error("[trade-manager] Error:", error);
    return new Response(
      JSON.stringify({ error: error instanceof Error ? error.message : "Unknown error" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

